INSERT INTO `sach` (`id`, `tieu_de`, `isbn`, `nam_xuat_ban`, `so_trang`, `tac_gia_id`, `nha_xuat_ban_id`, `nha_cung_cap_id`, `the_loai_id`, `loai_sach`, `hinh_thuc_bia`, `mo_ta`, `file_anh_bia`, `link_anh_bia`, `gia_ban`, `gia_goc`, `so_luong_ton`, `created_at`, `updated_at`) VALUES
(379, 'Bộ Nếu Biết Trăm Năm Là Hữu Hạn - Ấn Bản Kỉ Niệm 10 Năm Xuất Bản (Tái Bản 2024)', '8932000134749', '2024', 263, 111, 7, 32, 6, 'trong_nuoc', 'Bìa Mềm', 'NẾU BIẾT TRĂM NĂM LÀ HỮU HẠN - LÁ THƯ GỬI NHỮNG NGƯỜI TRẺ ĐANG LẠC LỐI\nBạn đã bao giờ tự hỏi: Nếu biết trước cuộc đời là hữu hạn, bạn sẽ sống khác đi chứ? \nChúng ta luôn nghĩ mình có nhiều thời gian, nhưng thực tế, mọi khoảnh khắc đều đang trôi qua mãi mãi.\nVỀ TÁC GIẢ: PHẠM LỮ ÂN\nLà bút danh của đôi vợ chồng nhà báo chuyên viết cho giới trẻ, là Đặng Nguyễn Đông Vy và Nguyễn Hoàng Mai, hai nhà văn nổi bật trong dòng sách truyền cảm hứng.\nNhững tác phẩm của họ không chỉ là lời kể, mà là những triết lý sống sâu sắc, giúp độc giả nhìn lại chính mình.\nNếu Biết Trăm Năm Là Hữu Hạn là một trong những cuốn sách được yêu thích nhất, giúp hàng ngàn người trẻ tìm lại ý nghĩa của cuộc sống.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8932000134749_1.jpg', 143000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(380, 'Trốn Lên Mái Nhà Để Khóc - Tặng Kèm Bookmark', '8935325015984', '2023', 208, 112, 2, 14, 6, 'trong_nuoc', 'Bìa Mềm', 'TRỐN LÊN MÁI NHÀ ĐỂ KHÓC - NƠI CẢM XÚC ĐƯỢC BUÔNG LỎNG, KÝ ỨC ĐƯỢC CẤT LỜI\n\"Có những ngày chẳng ai hiểu mình, chẳng ai cần mình, chẳng ai thương mình. Và những ngày đó, mái nhà là nơi duy nhất tôi thấy an toàn.\"\n\"Trốn Lên Mái Nhà Để Khóc\" không chỉ là câu chuyện của riêng tác giả, mà còn là những mảnh ghép ký ức của mỗi người. Một cuốn sách dành cho những trái tim nhạy cảm, cho những ai từng giấu nước mắt sau nụ cười, từng thu mình vào một góc chỉ để đối diện với chính mình.\n  VỀ TÁC GIẢ: Lam\nTác giả trẻ, nổi bật với lối viết tinh tế, giàu cảm xúc.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/b/_/b_a-1-tr_n-l_n-m_i-nh_-_-kh_c-2.jpg', 80500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(381, 'Người Bình Thường Tập Lớn', '8935325034206', '2026', 168, 113, 1, 10, 6, 'trong_nuoc', 'Bìa Mềm', 'Người Bình Thường Tập Lớn\n“SỐNG MỘT ĐỜI CỐ GẮNG KHÔNG NHẤT THIẾT PHẢI RỰC RỠ”\nTrong những năm tháng tuổi trẻ, hẳn chúng ta đã từng không ít lần nhìn thấy bạn bè đồng trang lứa thành công, tỏa sáng mà cảm thấy áp lực, tự ti, thất vọng về bản thân. Thực ra “Sống một cuộc đời rực rỡ phi thường cũng tốt, nhưng nhỏ bé bình thường cũng chẳng sao. Nếu so sánh mình với những người thành công hay tài năng xuất chúng, em chỉ thấy mình nhỏ bé như hạt cát giữa sa mạc.”\n“Người bình thường tập lớn” là những lời nhắn nhủ nhẹ nhàng, chân thành của tác giả Maii gửi đến mọi người rằng làm một người bình thường cũng tốt. Hạnh phúc đơn giản lắm, đó là được làm công việc mình thích, được ăn cơm mẹ nấu, được gặp những người tử tế. Chỉ cần bạn không còn so sánh cuộc đời của mình với người khác, bạn mới thật sự đang sống cuộc đời của chính mình.\nVấp ngã hay thất tình cũng chỉ là một phần của hành trình trưởng thành. Làm một người bình thường nhưng có một tâm hồn giàu có và tử tế, đó đã là một loại thành công rực rỡ nhất rồi.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/b/_/b_a-1-ng_i-b_nh-th_ng-t_p-l_n.jpg', 73500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(382, 'Mẹ Làm Gì Có Ước Mơ', '8935325011047', '2023', 208, 114, 1, 10, 6, 'trong_nuoc', 'Bìa Mềm', '“Ước mơ của mẹ là gì?”\n“Thì cho chúng mày ăn học đàng hoàng, đầy đủ để mai sau đỡ khổ.”\n“Không, ước mơ khác cơ.”\n“Mai sau chúng mày lập gia đình, chọn được đúng người, vợ chồng yêu thương nhau.”\n“Ước mơ dành riêng cho bản thân mẹ cơ mà.”\n“MẸ THÌ LÀM GÌ CÓ ƯỚC MƠ.”\nBạn có bao giờ hỏi ước mơ của bố mẹ là gì? Hoặc dù có hỏi bố mẹ cũng chỉ trả lời qua loa như “Làm gì có…”. Nhưng bạn biết không, làm gì có ai trên thế giới này không có ước mơ cơ chứ, chỉ là ước mơ của bố mẹ chúng ta được cất giấu rất sâu trong tim và đánh đổi bằng nụ cười của những đứa con mà thôi.\nTại sao mẹ lại chẳng có nổi một ước mơ cho riêng mình? Phải chăng gánh vai mẹ đã quá mỏi mệt với cơm áo gạo tiền, với những bữa ăn và học phí của con.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/8/98bde27a91ea4bb412fb.jpg', 66500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(383, 'Nơi Nào Có Mẹ - Nơi Ấy Là Nhà - Tặng Kèm Bookmark', '8935325019395', '2024', 192, 114, 1, 10, 6, 'trong_nuoc', 'Bìa Mềm', 'Nơi Nào Có Mẹ - Nơi Ấy Là Nhà\nTrên đời này, sẽ chẳng có ai vì bạn quan tâm mà hỏi “Dạo này con làm gì, dạo này con có đủ tiền không, dạo này con có ăn uống đầy đủ không?”... ngoại trừ MẸ của bạn.\nTrên đời này, sẽ chẳng có ai sẵn sàng mua những thứ tốt nhất cho bạn dù họ có thể cả năm không mua lấy một bộ quần áo mới… ngoại trừ MẸ của bạn.\nTrên đời này, sẽ chẳng có ai cho bạn những bữa ăn miễn phí, yêu thương bạn vô điều kiện…ngoại trừ MẸ của bạn.\nĐúng thật là “thế gian rộng lớn, có mẹ là đủ”, nơi chúng ta muốn quay trở về để được chữa lành, được an ủi. Dù cả thế giới có bỏ mặc bạn, vẫn dám chắc chắn một điều, trong lòng mẹ, bạn chính là cả thế giới.\nNƠI NÀO CÓ MẸ, NƠI ẤY LÀ NHÀ là lời nhắn mà tác giả Hạ Mer gửi đến tất cả chúng ta: Khi bạn tìm hoài chẳng thấy hạnh phúc, về nhà đi! Nơi có Mẹ, có một mâm cơm ấm, một vòng tay êm, một góc sân nhỏ. Nơi có mẹ tựa một gốc đại thụ che trời, luôn đóng vai trầm mặc, che gió, che mưa cho bạn, sẵn sàng hy sinh mọi thứ mà không cần hồi đáp.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/z/5/z5288994344245_f98249489626ef768c679043558bebee.jpg', 67500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(384, 'Đám Trẻ Ở Đại Dương Đen (Tái Bản 2026)', '8935325034237', '2026', 280, 115, 7, 10, 6, 'trong_nuoc', 'Bìa Mềm', 'Đám Trẻ Ở Đại Dương Đen\n“nỗi buồn không rõ hình thù\nta cho nó dáng, ta thu vào lòng\nta ôm mà chẳng đề phòng\nmột ngày nó lớn chất chồng tâm can”\n“kẻ sống muốn đời cạn\nngười chết muốn hồi sinh\ntrần gian bi hài nhỉ?\nta còn muốn bỏ mình?”', NULL, 'https://cdn1.fahasa.com/media/catalog/product/_/m/_m-tr_-_-_i-d_ng-_en_-b_a-1.jpg', 95000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(385, 'Khói Trời Lộng Lẫy (Tái Bản 2022)', '8934974175346', '2022', 144, 116, 27, 24, 6, 'trong_nuoc', 'Bìa Mềm', 'Khói Trời Lộng Lẫy (Tái Bản 2022)\nCác truyện trong tập đều xoay quanh thân phận người phụ nữ. Nỗi buồn bao quanh họ: cô đơn, khao khát tình cảm gia đình, tình yêu. Không được hạnh phúc, đôi khi họ tỏ ra \"cay nghiệt\", nhưng rồi sự cay nghiệt cũng không vượt quá sự mong manh yếu đuối vốn là bản chất của họ (như cô gái trong Khói Trời Lộng Lẫy đã đánh cắp đứa em trai cùng cha khác mẹ để trả thù người cha bỏ rơi mình, để rồi cuối cùng lâm vào tình trạng tiến thoái lưỡng nan).\nCác nhân vật của Nguyễn Ngọc Tư được sinh ra để đi tìm nhau. Cho nên, cùng với nỗi mất mát, cô cũng cho họ những con đường, đó là lòng vị tha và một chút hy vọng.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/k/h/khoi-troi-long-lay-tb-2022.jpg', 67500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(386, 'Bài Học Của Vũ Trụ (Tái Bản 2025)', '9786044161884', '2025', 118, 117, 13, NULL, 6, 'trong_nuoc', 'Bìa Mềm', 'Bài Học Của Vũ Trụ\nTôi cũng như bao nhiêu con người bình thường khác, trải nghiệm cuộc sống này từ lúc chán ghét nó cho đến nhận ra sự hoàn hảo và kì diệu của nó.\nChính vì vậy, tôi mang hết sự dũng cảm của mình để chiến đấu với sự tự ti của bản thân, chiến đấu với sự sợ hãi bị đánh giá thấp từ người khác, với sự cứng đầu và bản năng thích kiểm soát của mình để kể cho bạn nghe những câu chuyện thức tỉnh của riêng tôi.\nTôi không cần biết rằng cuốn sách này có bán chạy hay không, cũng không cần biết cuốn sách này có giúp tôi trở nên giàu có hay không, vì đó không phải là mục đích ban đầu của tôi. Tôi chỉ cần biết là tôi đã chiến thắng chính bản thân mình. Đức Phật nói: \"Chiến thắng bản thân mới là chiến thắng đáng tự hào nhất\".', NULL, 'https://cdn1.fahasa.com/media/catalog/product/b/i/bi_a-s_ch-_n---b_i-h_c-c_a-v_-tr__1.jpg', 108000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(387, 'Khai Tâm Chuyển Vận - Vận Mệnh Đổi Thay Từ Tâm Thức Đúng', '8935325018565', '2024', 344, 118, 7, 10, 6, 'trong_nuoc', 'Bìa Mềm', 'Khai Tâm Chuyển Vận - Vận Mệnh Đổi Thay Từ Tâm Thức Đúng\nNăm 2024, thế giới bước vào năm đầu tiên của vận 9 do sao Cửu Tử nắm quyền. Trong số học, số 9 là con số cực đại. Và đúng theo chu trình thì khi vạn vật phát triển tới cực thịnh thì sẽ dần suy bại để bắt đầu một chu trình mới. Do đó, những năm cuối thời kỳ này, có lẽ chiến tranh và dịch bệnh sẽ xảy ra còn kinh khủng hơn giai đoạn vận 8.\nVận 9 là giai đoạn mà xã hội loài người có nhiều chuyến biến, trong khi sao Cửu Tử là sao trung tính, nên chuyển biến tích cực hay tiêu cực phụ thuộc vào ý chí của con người cũng như quy luật âm dương và ngũ hành. Muốn cải mệnh, bạn cần phải hiểu về quy luật vận hành của trời đất và tính cách, vận mệnh của bản thân - những điều sẽ được giải mã trong cuốn sách Khai tâm chuyển vận - Vận mệnh đổi thay từ tâm thức đúng.\nKhai tâm chuyển vận - Vận mệnh đổi thay từ tâm thức đúng được chia thành ba phần dựa trên Thuyết Tam Tài của Nho giáo phương Đông.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/_/k/_khai-t_m-chuy_n-v_n_-b_a-1.jpg', 99000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(388, 'Chí Phèo (2017)', '8935095623945', '2017', 206, 119, 16, 4, 6, 'trong_nuoc', 'Bìa Mềm', 'Chí Phèo\nChí Phèo là một truyện ngắn nổi tiếng của nhà văn Nam Cao viết vào tháng 2 năm 1941. Chí Phèo là một tác phẩm xuất sắc, thể hiện nghệ thuật viết truyện độc đáo của Nam Cao, đồng thời là một tấn bi kịch của một người nông dân nghèo bị tha hóa trong xã hội. Hiện nay, truyện đã được đưa vào sách giáo khoa Ngữ Văn 11, tập 1. Chí Phèo cũng là tên nhân vật chính của truyện.\nTruyện ngắn Chí Phèo, nguyên có tên là Cái lò gạch cũ; khi in thành sách lần đầu năm 1941, Nhà Xuất bản Đời mới - Hà Nội tự ý đổi tên là Đôi lứa xứng đôi. Đến khi in lại trong Tập Luống cày (do Hội Văn hóa cứu quốc xuất bản, Hà Nội, 1946), Nam Cao đặt lại tên là Chí Phèo.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_193731.jpg', 38000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(389, 'Chuyện ICU - Lá Gan Hạnh Phúc', '9786047789955', '2023', 297, 120, 15, 33, 6, 'trong_nuoc', 'Bìa Mềm', 'Chuyện ICU - Lá Gan Hạnh Phúc\nQuyển sách \"Chuyện ICU - Lá gan hạnh phúc\" là tập truyện ngắn được Bác sĩ Wynn viết về những tháng ngày làm việc tại khoa ICU khi chứng kiến nhiều cái chết, nhiều sự ra đi đầy nuối tiếc. Mời quý vị cùng trải nghiệm những cung bậc của sức chịu đựng, sự đau đớn, lòng vị tha, sự tử tế và tình yêu.\nICU (Intensive Care Unit, Khoa chăm sóc đặc biệt) bao gồm các bệnh nặng nhất, nguy hiểm nhất đến tính mạng như đột quỵ, nhồi máu cơ tim, tai nạn giao thông, nhiễm trùng toàn thân hay suy hô hô hấp cấp tính.\nĐây là nơi có tỉ lệ tử vong cao nhất bệnh viện. Tất cả bệnh nhân vào ICU chỉ có hai hướng: lên các tầng trên khi bệnh đã thuyên giảm hoặc đi xuống nhà xác tầng hầm. Trung bình, mười bệnh nhân vào ICU, ba người sẽ theo thang máy xuống dưới\n---', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/7/9786047789955.jpg', 111500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(390, 'Những Chú Mèo Nơi Thị Trấn Ulthar - Tuyển Tập H. P. Lovecraft - Tặng Kèm Postcard', '9786042251839', '2025', 84, 121, 4, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Những Chú Mèo Nơi Thị Trấn Ulthar - Tuyển Tập H. P. Lovecraft\n“Kuranes chỉ kiếm tìm cái đẹp. Khi sự thật và trải nghiệm không thể hé lộ nó, ông đi tìm trong trí tưởng tượng cùng ảo tưởng, và tìm thấy nó kề cận sát sườn, giữa những kí ức mơ hồ về các câu chuyện với giấc mơ thời thơ ấu.”\nẨn sâu trong tiềm thức con người là một thế giới không ai có thể bước vào bằng đôi chân, mà phải thông qua những giấc mơ. Đó là Mộng Giới huyền bí được H. P. Lovecraft dệt nên từ chiêm bao, kí ức và nỗi sợ xưa cũ, với các thành phố vĩnh hằng lơ lửng giữa thời không cùng những thực thể cổ xưa quan sát thế giới từ sau bức màn mộng tưởng.\nKhông đơn thuần là một thế giới trong cơn mơ, Mộng Giới là hành trình vào phần sâu thẳm nhất của trí tưởng tượng – nơi cái đẹp và nỗi kinh hoàng hoà quyện. Một không gian vừa lộng lẫy mê hoặc như mộng, vừa thấp thoáng nguy hiểm như chính tâm thức nhân loại.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/n/h/nhung-chu-meo-noi-thi-tran-ulthar_qua-tang.jpg', 34000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(391, 'Đồng Hành Là Lời Tỏ Tình Chân Thành Nhất - Bản Đặc Biệt - Tặng Kèm Bookmark + Postcard', '3300000060958', '2026', 144, 122, 10, 14, 6, 'trong_nuoc', 'Bìa Mềm', 'Đồng Hành Là Lời Tỏ Tình Chân Thành Nhất\nGiữa một thế giới mà những lời thề non hẹn biển đôi khi đến và đi nhanh như một cái chớp mắt, có bao giờ bạn lặng yên tự hỏi: Điều gì mới thực sự giữ hai trái tim ở lại bên nhau bền bỉ qua năm tháng?\nCâu trả lời, hóa ra chẳng nằm ở những món quà xa xỉ hay những lời hoa mỹ xa xôi mà gói gọn trong hai chữ mà đôi khi ta vô tình lãng quên: Đồng hành.\n“Đồng hành là lời tỏ tình chân thành nhất” - Cuốn sách mới nhất của tác giả Trinh Nguyễn (23thang12) tựa như một thước phim chậm, một \"tập thư\" cũ kỹ cất giấu những tâm tư vụn vỡ mà chúng ta thường chỉ dám nghĩ đến khi đêm về. Được viết bằng tất cả sự thành thật từ những dòng ghi chú tự an ủi chính mình của chính tác giả, mỗi trang viết sẽ là một cái chạm khẽ khàng vào những nỗi đau ta chưa kịp gọi tên.\nLật mở từng chương trong “Đồng hành là lời tỏ tình chân thành nhất”, bạn sẽ được dẫn dắt qua hành trình của “Em”, của “Anh” và một cái “Kết” không ồn ào nhưng đủ đầy - nơi tình yêu được nhìn bằng con mắt trưởng thành hơn. Đó là tiếng lòng của một cô gái đã từng yêu sâu đậm, từng biết đau đến xé lòng, nhưng cuối cùng đã học được cách bao dung cho chính mình. Đó là sự thấu cảm sâu sắc khi ta học cách đặt trái tim mình vào vị trí của người thương, thay vì chỉ lo lắng cho những hỉ nộ ái ố của riêng mình.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/c/b/cbb---b_n-_c-bi_t.jpg', 72000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(392, 'Nếp Nhà - Từ Gốc Rễ Đến Ngọn Gió', '8935278609605', '2025', 296, 123, 5, 20, 6, 'trong_nuoc', 'Bìa Mềm', 'Nếp Nhà - Từ Gốc Rễ Đến Ngọn Gió\nNếp nhà - Khi những giá trị của gia đình làm nên tất cả\n\"Nếp Nhà - Từ Gốc Rễ Đến Ngọn Gió\" của tác giả Nguyễn Hồng Phương là một tác phẩm sâu sắc, khéo léo lồng ghép giữa những câu chuyện gia đình giản dị và những triết lý sống quý báu. Cuốn sách không chỉ là hành trình khám phá những giá trị cốt lõi của gia đình mà còn là một kim chỉ nam cho những ai mong muốn gìn giữ sự gắn kết giữa các thế hệ trong bối cảnh xã hội hiện đại.\nTác giả Nguyễn Hồng Phương, một tiến sĩ ngành Công nghệ Thông tin tại trường CNAM, Paris, Pháp với hơn 25 năm kinh nghiệm trong lĩnh vực giáo dục, đã dành trọn tâm huyết để viết lên cuốn sách này. Tác giả không chỉ chia sẻ những trải nghiệm cá nhân mà còn mở ra một không gian kết nối, nơi những giá trị truyền thống được tôn vinh và hiện đại hóa.\nSách gồm 10 chương, được chia thành 3 phần, như một hành trình từng bước đi gốc rễ đến ngọn gió:', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/f/9f8b5630e51b4b9921bd89c95f4e34a9.jpg', 203150.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(393, 'Công Bằng Trên Đời Là Do Bạn Nỗ Lực Giành Lấy', '9786044011912', '2024', 280, 124, 2, 29, 6, 'trong_nuoc', 'Bìa Mềm', 'Công Bằng Trên Đời Là Do Bạn Nỗ Lực Giành Lấy\nGIỚI THIỆU TÁC GIẢ:\nMao Mao Trùng Tiểu Thư: Tên thật là Trang Lệ Cúc, là một tác giả trẻ tiêu biểu với hàng vạn người hâm mộ cùng nhiều bài viết nổi tiếng được đăng báo chỉ sau một năm viết lách.\nBằng kinh nghiệm phong phú và một trái tim ấm áp, những câu chuyện của cô đã khơi dậy động lực và truyền cảm hứng cho nhiều bạn trẻ.\nGIỚI THIỆU TÁC PHẨM:\n“CÔNG BẰNG TRÊN ĐỜI LÀ DO BẠN NỖ LỰC GIÀNH LẤY”\nĐôi khi chúng ta đều tự hỏi, tại sao cứ phải liều mạng, thảnh thơi sống qua ngày cũng là sống mà nhỉ? Song, chỉ cần nghĩ thế giới này to lớn vô cùng, phong cảnh muôn màu muôn sắc, bạn sẽ không cam lòng.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/c/_/c_ng-b_ng-tr_n-_i-do-b_n-n_-l_c-gi_nh-l_y-_1_.jpg', 79000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(394, 'Tạp Văn Nguyễn Ngọc Tư (Tái Bản 2020)', '8934974168607', '2020', 193, 116, 27, 24, 6, 'trong_nuoc', 'Bìa Mềm', '\"Tạp văn Nguyễn Ngọc Tư\" khiến cho người ta thấy rằng nhà văn trẻ có thể biến mọi đề tài \"tầm thường\" trở thành thời sự. Ẩn sau \"giọng nói\" trong trẻo, duyên dáng của một cô gái là sự trải nghiệm về thời cuộc, đời sống dân dã và chiều sâu văn hoá của vùng đất cực Nam Tổ quốc... NXB Trẻ trân trọng giới thiệu cùng bạn đọc.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_48173.jpg', 67500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(395, 'Khi Hai Ta Về Một Nhà', '8935325026508', '2025', 152, 125, 10, 14, 6, 'trong_nuoc', 'Bìa Mềm', 'Khi Hai Ta Về Một Nhà\nCảm giác được “về chung một nhà” với người mình thương là như thế nào nhỉ?\nLà khi ban công có những chậu cây em thích, nhưng anh lại là người tưới nước mỗi ngày. Trong tủ quần áo sẽ có váy dài của em xen lẫn sơ mi của anh. Bàn chải đánh răng đặt cạnh chung chỗ, chìa khóa nhà có đôi. Cơm lúc nào cũng nóng, trong bình luôn sẵn trà thơm.\nAnh đi, em nhớ. Em về, anh vui. Vậy là thành nhà!\nNếu bạn tò mò về cảm giác ngọt ngào ấy, thì hãy lật mở “Khi Hai Ta Về Một Nhà” – Cuốn sách đầu tay của cặp đôi Content Creator Ông Thỉ Bà Long nhé! Cuốn sách sẽ đưa bạn vào hành trình của tình yêu với đầy đủ những dư vị ngọt ngào, mâu thuẫn và cả sự trưởng thành của cả hai trong mối quan hệ. 152 trang sách trong “Khi Hai Ta Về Một Nhà” là những câu chuyện chân thực mà bất cứ ai cũng có thể tìm thấy bóng dáng của chính mình: Những khoảnh khắc hạnh phúc giản đơn, những lần giận hờn tưởng chừng xa cách, và cả cách để giữ nhau “thật chặt”.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/b/_/b_a-1_4_30.jpg', 83000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(396, 'Vợ Nhặt (Tái Bản 2025)', '8936238101030', '2025', 232, 126, 1, 5, 6, 'trong_nuoc', 'Bìa Mềm', 'Vợ Nhặt\nKim Lân tên thật là Nguyễn Văn Tài, sinh ngày 1 tháng 8 năm 1920.\nÔng quê ở làng Phù Lưu, xã Tân Hồng, huyện Từ Sơn (nay là làng Phù Lưu, phường Đông Ngàn, thị xã Từ Sơn), tỉnh Bắc Ninh. Do hoàn cảnh gia đình khó khăn, ông chỉ được học hết bậc tiểu học rồi phải đi làm. Kim Lân bắt đầu viết truyện ngắn từ năm 1941. Một số truyện (Vợ nhặt, Đứa con người vợ lẽ,...) mang tính chất tự truyện nhưng đã thể hiện được không khí tiêu điều, ảm đạm của nông thôn Việt Nam và cuộc sống lam lũ, vất vả của người nông dân thời kì đó.\nSau Cách Mạng tháng Tám, Kim Lân tiếp tục làm báo, viết văn. Ông vẫn chuyên về truyện ngắn và vẫn viết về làng quê Việt Nam - mảng hiện thực mà từ lâu ông đã hiểu biết sâu sắc. Những tác phẩm chính: Nên vợ nên chồng (tập truyện ngắn, 1955), Con chó xấu xí (tập truyện ngắn, 1962).\nTập truyện ngắn “Vợ nhặt” tập hợp những truyện ngắn đặc sắc nhất của Kim Lân – một cây bút truyện ngắn vững vàng, viết về cuộc sống và con người ở nông thôn bằng tình cảm, tâm hồn của một người vốn là con đẻ của đồng ruộng.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/t/h/thiet_ke_chua_co_ten__81__51d105537c8544b8945d7e1eb59d57fb_master.jpg', 45000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(397, 'Thưa Ngoại Con Mới Về - Tặng Kèm Bookmark', '8935325023583', '2024', 216, 112, 2, 14, 6, 'trong_nuoc', 'Bìa Mềm', 'Thưa Ngoại Con Mới Về\n“Trong những tháng ngày lớn lên, có ai đó đã an ủi tôi rằng: “Khi rời đi, người thương của bạn sẽ hóa thành một vì sao lấp lánh.” Ngày ấy tôi không thích lời an ủi đó lắm, vì tôi chẳng thể tìm được vì sao nào trên bầu trời thành phố nơi tôi sống, dù đêm đó trăng có sáng hay không. Mãi sau này tôi mới hiểu, có những vì sao không mọc trên bầu trời, không thể nhìn bằng mắt thường, không thể chụp bằng điện thoại, bởi vì những vì sao ấy mọc ở trong tim.”\nĐó là những dòng viết đầy xúc động trong cuốn sách mới nhất của tác giả Lam - “Thưa ngoại con mới về”, một cuốn sách viết về những điều giản dị mà thiêng liêng, về ông bà, gia đình - nơi lưu giữ những yêu thương nguyên sơ và bình yên nhất.\nNếu như \"Trốn lên mái nhà để khóc\" đã từng chạm đến trái tim HÀNG VẠN ĐỘC GIẢ bằng cách tiếp thêm cho chúng ta can đảm để đối mặt với những tổn thương, thì “Thưa ngoại con mới về” sẽ nhẹ nhàng nắm tay bạn, đưa bạn trở về với miền ký ức êm đềm của tuổi thơ. Nơi có mùi hương ấm áp của ông bà, của những bữa cơm gia đình, của tiếng cười giòn tan bên bếp lửa hồng. Nơi mà có lẽ, mỗi chúng ta đều vô tình lãng quên khi bị cuốn đi theo dòng chảy xô bồ của thời gian, hoặc buộc phải rời xa khi “làm một người trưởng thành”.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/z/5/z5919252030585_22f8867c87aacc0e58cbdba585ca9e1d.jpg', 89000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(398, 'Thành Phố Thiếu Một Bữa Cơm Nhà', '9786326042023', '2025', 208, 127, 7, 29, 6, 'trong_nuoc', 'Bìa Mềm', 'Thành Phố Thiếu Một Bữa Cơm Nhà\nMỹ Hưng - admin kênh GenZ tập lớn: Một người bình thường phải lòng trước những điều dễ thương.\nHồng Nhung - admin kênh Ánh nến đức tin: Chỉ là người nói hộ lòng ai đó.\nGIỚI THIỆU TÁC PHẨM\nCuốn sách dành tặng bạn, đứa trẻ đã lớn, đã đi xa và nhớ quay quắt “bữa cơm nhà”.\nDành tặng những đêm bạn tủi thân, khẽ lau nước mắt trong căn phòng trọ vắng người.\nCuốn sách giúp bạn thêm yêu gia đình và biến tình yêu đó thành động lực để cố gắng!\n\"Thành phố có rất nhiều món ngon, nhưng chẳng món nào ngon bằng cơm của mẹ!\"\nĐã bao lần bạn bước ra khỏi công ty lúc trời tối mịt, tay cầm túi đồ ăn mua vội, chân lê về căn phòng trọ lặng lẽ, nơi không có ai chờ, không có bữa cơm nào đang ấm sẵn, không có tiếng ai gọi bạn “về ăn cơm đi con”?', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/7/9786326042023.jpg', 66000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(399, 'Tôi Thích Dáng Vẻ Nỗ Lực Của Chính Mình', '9786044059761', '2024', 208, 128, 2, 29, 6, 'trong_nuoc', 'Bìa Mềm', 'Tôi Thích Dáng Vẻ Nỗ Lực Của Chính Mình\nGIỚI THIỆU TÁC GIẢ:\nLILY TRƯƠNG\nLà một người hướng nội INFJ, tác giả tự do, freelance writer và nhà sáng tạo nội dung đa nền tảng. Cô từng theo học ngành luật, hiện tại, cô tập trung nghiên cứu và viết về lĩnh vực tâm lý, giáo dục và sự phát triển cá nhân.\nĐồng thời cô cũng là chủ kênh growthwithlily - kênh chia sẻ những nội dung về học tập, năng suất và phát triển bản thân với hơn 100.000 lượt theo dõi.\nGIỚI THIỆU TÁC PHẨM:\nNẾU ÔNG TRỜI KHÔNG BAN CHO BẠN SỰ MAY MẮN, VẬY HÃY TỰ BIẾN BẢN THÂN MÌNH THÀNH “KỲ TÍCH”', NULL, 'https://cdn1.fahasa.com/media/catalog/product/4/0/40eebd4668f7f312da5486d5804cc24e.jpg', 79000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(400, 'Hai Mặt Của Gia Đình (Tái Bản 2025)', '8935325027482', '2025', 288, 129, 7, 10, 6, 'trong_nuoc', 'Bìa Mềm', 'Hai Mặt Của Gia Đình\nTại sao chúng ta lại chịu tổn thương bởi gia đình – những người gần chúng ta nhất?\nTại sao dù ở cạnh gia đình nhưng bạn vẫn cảm thấy xa cách và cô đơn?\nVì sao chúng ta luôn bộc phát cảm xúc khi đứng trước gia đình mình. Vì sao nỗi đau của gia đình nơi bạn sinh ra và lớn lên lại lặp lại trong gia đình hiện tại? Nhiều khi những tổn thương đến từ gia đình nơi chúng ta sinh ra và lớn lên lại chính là nguyên nhân của các vấn đề trong gia đình hiện tại.\nGia đình trở thành nơi tiếp thêm sức mạnh và cũng là nơi khiến đôi vai chúng ta thêm nặng trĩu, là nơi ẩn náu của những mâu thuẫn tinh vi đằng sau những phút giây thân mật, là nơi tràn đầy thương yêu nhưng có cả sự ghét bỏ. Gia đình lúc nào cũng có hai mặt như vậy.\nChoi Kwang Huyn – một nhà tâm lý học hàng đầu Hàn Quốc, người đã tham vấn tâm lý cho rất nhiều trường hợp có khúc mắc về tổn thương tâm lý xuất phát từ gia đình sẽ chỉ ra nguyên nhân của những tổn thương, những nỗi đau mà chúng ta phải chịu từ gia đình mình, đồng thời đưa ra cách giải quyết đối với các vấn đề gia đình nhức nhối hiện tại.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/b/_/b_a-1---hai-m_t-c_a-gia-_nh.jpg', 96500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(401, 'Tủ Sách Văn Học Trong Nhà Trường - Truyện Ngắn Nguyễn Công Hoan (Tái Bản 2025)', '8935352621721', '2025', 252, 130, 4, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Tủ Sách Văn Học Trong Nhà Trường - Truyện Ngắn Nguyễn Công Hoan\n“Nguyễn Công Hoan có một vị trí vững vàng, đầy vinh dự trong lịch sử văn học dân tộc. Ông là một trong số những nhà văn đặt nền móng cho chủ nghĩa hiện thực trong văn học Việt Nam 1930 - 1945. Ông cũng là nhà văn có đóng góp quan trọng trong việc mở đường và phát triển thể loại truyện ngắn hiện đại, đặc biệt là truyện ngắn trào phúng, đưa nó tới một tầm cao mà cho tới nay, chưa có cây bút nào sánh nổi.” (Tiến sĩ TRẦN ĐĂNG SUYỀN)\n“Trong kho tàng truyện ngắn của dân tộc, Nguyễn Công Hoan đã đóng góp một khối lượng lớn và có một nghệ thuật khá điêu luyện. Đi vào thế giới truyện ngắn của Nguyễn Công Hoan, ta có cảm tưởng như bước vào một khu triển lãm phong phú, nhiều màu nhiều vẻ về những cảnh ngộ, những con người múa may, khóc cười trong xã hội cũ.” (Giáo sư PHAN CỰ ĐỆ)\nMời các bạn tìm đọc TỦ SÁCH VĂN HỌC TRONG NHÀ TRƯỜNG', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_12615_1.jpg', 55000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(402, 'Bộ Kính Vạn Hoa - Tập 15 - Khách Sạn Hoa Hồng - Quà Tặng Ba Lần - Kính Vạn Hoa (Tái Bản 2022)', '8935244864380', '2022', 328, 54, 17, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Kính Vạn Hoa - Tập 15: Khách Sạn Hoa Hồng - Quà Tặng Ba Lần - Kính Vạn Hoa (Tái Bản 2022)\n“Trong dòng chảy văn học thiếu nhi Việt Nam, tên tuổi Nguyễn Nhật Ánh nổi lên như một “hiện tượng tác giả” đặc biệt. Các tác phẩm của nhà văn liên tục nối tiếp nhau ra đời khiến đời sống xuất bản và phát hành sách cho thiếu nhi sôi động hẳn lên. Bằng tài năng của mình, “chàng hoàng tử trong thế giới tuổi thơ” luôn được bạn đọc nhỏ tuổi và cả các bậc phụ huynh từ Bắc chí Nam đón nhận một cách nhiệt tình. Các sáng tác của Nguyễn Nhật Ánh đề cập đến nhiều vấn đề, nhiều khía cạnh liên quan đến cuộc sống của các em, từ môi trường gia đình, học đường đến những suy nghĩ riêng tư, những rung động đầu đời của tuổi mới lớn. Không chỉ là người quan sát và trải nghiệm tinh tế, Nguyễn Nhật Ánh đã hòa mình, “nhập thân” vào chính đối tượng miêu tả để làm nên sức cuốn hút qua những trang văn sinh động, phong phú, nhiều màu sắc của mình.”\nNhà phê bình văn học LƯU KHÁNH THƠ\n(Báo Thanh Niên, 7-7-2013)', NULL, 'https://cdn1.fahasa.com/media/catalog/product/k/i/kinh-van-hoa---phien-ban-moi---tap-15---tb-2022.jpg', 73000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(403, 'Bộ Sách Tương Tác - Thỏ Con Tương Tác, Sáng Tạo', '8936072917286', NULL, NULL, 62, 12, 22, 6, 'trong_nuoc', 'Bìa Cứng', 'Bộ Sách Tương Tác - Thỏ Con Tương Tác, Sáng Tạo\n\"Thỏ con tương tác sáng tạo\" là bộ sách tương tác phát triển kỹ năng toàn diện dành cho bé từ 6 tháng tuổi. Mỗi cuốn sách tạo ra bối cảnh quen thuộc (giờ đi ngủ, đi tắm, bị thương) và đưa ra các lời mời trẻ tương tác với trang sách. Trẻ sẽ tìm thấy niềm vui bất tận trong mỗi lần đọc sách và những bài học kỹ năng sống sẽ theo những niềm vui ấy tự nhiên thấm vào trí nhớ của trẻ.\nBộ sách tương tác phát triển kỹ năng toàn diện cho bé từ 6 tháng tuổi\n“Thỏ con đến giờ ngủ rồi” đạt được thành công vang dội ngay từ khi mới ra mắt với 60 ngàn bản và được dịch ra 6 ngôn ngữ. Nối tiếp câu chuyện cực kỳ sáng tạo, lôi cuốn về chú thỏ đáng yêu này, tác giả Jörg Mühle tiếp tục ra mắt hai cuốn sách “Thỏ con dũng cảm nín khóc” và “Thỏ con ngại gì tắm mát”, tạo thành bộ sách tương tác phát triển kỹ năng toàn diện cho trẻ.\nThỏ con đến giờ ngủ rồi: Cuốn sách mời trẻ cùng thực hiện các hoạt động tương tác vui nhộn trên từng trang như vỗ nhẹ vào vai Thỏ, gãi tai, xoa lưng cho Thỏ, hôn chúc ngủ ngon… để giúp Thỏ con đi ngủ. Thông qua các tương tác này, tâm trí của trẻ nhỏ sẽ được làm dịu lại sau một ngày nhiều cảm xúc, đưa trẻ vào giấc ngủ êm ái và chất lượng hơn.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/t/h/th_-con-t_ng-t_c_-s_ng-t_o---b_-s_ch-t_ng-t_c.jpg', 206190.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(404, 'Một Cuốn Sách Trầm Cảm', '8935325010071', '2022', 208, 73, 13, 10, 6, 'trong_nuoc', 'Bìa Mềm', 'Một Cuốn Sách Trầm Cảm\n“Ở nơi đây mình không bán nụ cười\nmình chỉ bán nước mắt và buồn hiu\nở nơi đây mình không bán tình yêu\nchỉ có cô liêu và những ngày quạnh quẽ.”\nMột cuốn sách trầm cảm hay còn có tên Một cuốn sách của macmart là quyển tản văn và thơ bộc bạch những tâm tư, cảm xúc của một người trẻ, một trái tim non dại, một tâm hồn chênh vênh, khắc khoải, đớn đau khi phải đối mặt với hiện thực cuộc sống từ những ngày biết tự ý thức cho đến những bước chân tập tễnh đầu tiên trên hành trình tự trưởng thành, mà chắc hẳn ai cũng từng một lần cảm thấy.\nBắt đầu bằng những câu chuyện kể, những lời độc thoại cô đơn với chính mình, nhưng rồi sự xuất hiện của gia đình, bạn bè, của những người xa lạ đã mang đến cho “đứa trẻ” muôn vàn cảm xúc khác biệt. Có thể là chút hy vọng nhỏ nhoi, cũng có thể là nỗi đau tột cùng hay sự thất vọng ngập tràn, tuy nhiên dường như bấy giờ tâm trạng của nhân vật đã không còn đơn độc. Từ đó, có sự xuất hiện của những biến đổi trong cảm xúc, trong chính con người thật của “đứa trẻ” ấy. Và cuối cùng là niềm hi vọng được nhìn thấy ánh sáng tích cực, chút niềm tin về cuộc sống bé nhỏ như một bông hoa mọc ra trên vách đá mà tác giả gửi gắm.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/m/o/motcuonsachtramcam1.jpg', 53000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(405, 'Mamma Moo Và Chú Quạ Rắc Rối - Mamma Moo Dựng Chòi', '8935095628483', '2019', 28, 61, 20, 4, 6, 'trong_nuoc', 'Bìa Mềm', 'Tình cờ bắt gặp một cái chòi do bọn trẻ dựng trên cây, Mamma Moo thích thú lắm và kiên quyết muốn làm một cái, bất chấp sự lo lắng và can ngăn của Quạ.\nNhưng cách dùng búa với cưa kiểu bò của Mamma Moo làm Quạ kinh hãi quá, Quạ buộc phải ra tay cho cô biết dựng chòi đúng điệu là như thế nào.\nTay nghề của Quạ có khá khẩm hơn Mamma Moo không? Chòi của Quạ và chòi của Mammo Moo, cái nào mới đẹp?\nCùng đọc Mamma Moo dựng chòi để biết rằng đôi khi, chỉ cần bắt tay làm hết sức, có vụng một tí cũng không hề gì!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_4367.jpg', 46000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(406, 'Tất Cả Các Dòng Sông Đều Chảy', '8935095620999', '2013', 508, 74, 1, 4, 6, 'trong_nuoc', 'Bìa Mềm', 'Tất Cả Các Dòng Sông Đều Chảy viết về cuộc đời của nữ họa sĩ Philadelphia diễn ra trên dòng sông Murray và darling, miền Nam nước Úc. Từ thuở hoa niên sống với dì dượng bên bờ sông, những ngày làm nữ thuyền trưởng duy nhất dọc ngang vùng Victoria, rồi đến lúc tuổi già bóng xế, đời cô gắn liền với nhịp đập của sông nước. Nhưng Tất Cả Các Dòng Sông Đều Chảykhông đơn thuần chỉ là chuyện kể về đời riêng của một con người. Ở đó chứa đựng những suy nghĩ rộng hơn, bao quát hơn và mang chất triết lý. Đời người như đời sông, như cuộc sống hòa tan với thời gian: luôn luôn trôi đi nhưng không ngừng đổi mới, mãi mãi biến chuyển nhưng muôn đời vẫn thế. Tất cả sông rồi sẽ đi về biển, từ biển bao la sẽ rót vào những lòng sông mênh mông tràn đầy, mạch luân lưu không ngơi nghỉ ấy là cuộc sống. Sẽ không bao giờ có cái chết vì nơi tận cùng cũng là khởi thủy cho những mầm sống mới.\n\"...Brenton nhìn Delie chăm chú biết bao, coi như muốn ghi nhớ từng nét mặt của cô hoặc như tìm đọc một câu trả lời cho một câu hỏi vẫn chưa đặt ra, làm cho Delie bối rối phải nhìn xuống.\n- Trễ quá rồi. Tôi phải đi...', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935095620999.jpg', 78000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(407, 'Bộ Kính Vạn Hoa - Tập 18 - Tóc Ngắn Tóc Dài - Má Lúm Đồng Tiền - Cà Phê Áo Tím (Tái Bản 2022)', '8935244864410', '2022', 336, 54, 17, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Kính Vạn Hoa - Tập 18: Tóc Ngắn Tóc Dài - Má Lúm Đồng Tiền - Cà Phê Áo Tím (Tái Bản 2022)\n“Nhân vật của Nguyễn Nhật Ánh như thoát khỏi trang sách, thành người đời, thành những đứa con của một bà mẹ nông dân miền Bắc. Bà mẹ ấy cùng chồng mình vào Sài Gòn kiếm sống. Từ đây bà điều đàn con bầy có tên chung là Kính Vạn Hoa mà bà kiếm được trong một tiệm sách cũ, điều ra mái tranh nghèo có đứa con đang thiếu mẹ, thiếu cha, để chính đàn con Kính Vạn Hoa kia thay bà nói về đất nước, về thành phố Hồ Chí Minh “nhộn nhịp nhưng cũng ấm áp tình thân”. Nhân vật văn học của Nguyễn Nhật Ánh không chỉ bước vào đời để chia sẻ gian khó - những gian khó riêng của mỗi gia đình và cả những gian khó của đất nước, trước và sau đổi mới mà còn đến để cùng vui với bạn đọc của mình, để cùng xây dựng vững chắc các gia đình, những thành phần cấu thành xã hội. Xin được trích một câu từ bài viết của bạn đọc: “Ba mẹ tôi, em tôi, chồng sắp cưới của tôi và bạn bè tôi đều gắn kết những tình thân nhờ niềm đam mê đối với bộ truyện Kính Vạn Hoa của tác giả Nguyễn Nhật Ánh.”\nNhà văn TRẦN QUỐC TOÀN', NULL, 'https://cdn1.fahasa.com/media/catalog/product/k/i/kinh-van-hoa---phien-ban-moi---tap-18---tb-2022.jpg', 73000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(408, 'Bộ Tanya Chiến Ký 4: Dabit Deus His Quoque Finem', '8935280913561', '2023', 536, 72, 9, 9, 6, 'trong_nuoc', 'Bìa Mềm', 'Dabit deus his quoque finem – Rồi Chúa cũng đặt dấu chấm hết cho những vấn đề này.\nMặt trận phương Nam của Đế quốc giành được nhiều lợi thế trước tàn dư của quân đội Cộng hoà – Nước Cộng hoà tự do. Nhờ những đóng góp vô cùng tích cực, Tanya và không đoàn của mình được hiệu triệu về đế đô. Những tưởng chuỗi ngày tận hưởng yên bình ở hậu phương đáng mơ ước của Tanya sắp tới, nào ngờ đấy lại là lệnh thuyên chuyển không đoàn của cô đến một chiến tuyến còn nguy hiểm hơn nhiều – Liên Bang.\nVùng lãnh thổ khép kín của những người theo chủ nghĩa cực tả cực đoan – Liên Bang, rõ ràng là nguy hiểm hơn nhiều so với một đội quân đã từng bại trận như Cộng hoà tự do. Không chỉ vậy, Liên Bang cũng từng được xem là một cường quốc cả về kinh tế và quân sự, đến mức dù luôn thiết lập quan hệ hợp tác hữu hảo với Liên Bang, nhưng quân đội Đế quốc vẫn luôn phải duy trì cụm tập đoàn quân phương đông cực kỳ hùng hậu và không di dịch bất cứ  một nguồn lực nào khỏi khu vực này, để đề phòng sự đe doạ từ người hàng xóm khó đoán này.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/z/4/z4162578203094_898f25f72bf0b21d61bad625aea45575.jpg', 135000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(409, 'Trống Thả Hình Đa Năng - DK580001', '8936178580506', '2020', NULL, NULL, NULL, 18, 6, 'trong_nuoc', NULL, 'Trống Thả Hình Đa Năng - DK580001\nĐồ chơi âm nhạc là món đồ chơi ưa chuộng và rất thích hợp cho trẻ sơ sinh và trẻ nhỏ, khoa học chứng minh trẻ nhỏ tiếp xúc với âm nhạc sớm sẽ thông minh, nhanh nhẹn hơn.\nBộ đồ chơi: Trống Thả Hình Đa Năng sẽ là món đồ chơi bổ ích cho trẻ sơ sinh và trẻ nhỏ trong những giai đoạn phát triển đầu đời.\nCảnh báo an toàn:\n- Trước khi sử dụng, hãy tháo bỏ bao bì nhựa và để xa tầm tay của trẻ\n- Nếu có bộ phận nào bị hư hại, hãy lập tức dừng sử dụng và để xa tầm với của trẻ', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8936178580506-1_1.jpg', 62500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(410, 'Cambridge English Qualifications - B1 Preliminary For Schools - 8 Practice Tests', '9786043350258', '2022', 255, 57, 19, NULL, 6, 'trong_nuoc', 'Bìa Mềm', 'Cambridge English Qualifications - B1 Preliminary For Schools - 8 Practice Tests\nAll the practice you need for a top score in B1 PRELIMINARY for Schools\n- Eight complete practice tests, for Reading, Writing, Listening and Speaking\n- Completely new practice tests that follow the updated exam format for 2020\n- A clear guide to the test and practical advice on how to revise and prepare\n- Online audio and audio scripts for the Listening and Speaking papers\n- Additional sample questions to help you prepare for the Speaking paper\n- Answers for all papers, including model answers for the Speaking and Writing papers', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/7/9786043350258.jpg', 285360.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(411, 'Bộ Hikaru - Kì Thủ Cờ Vây - Ultimate Edition - Tập 2 - Tặng Kèm Character Card', '9786042396189', '2026', 222, 67, 4, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Hikaru - Kì Thủ Cờ Vây - Ultimate Edition - Tập 2\nMột ngày mùa xuân, cậu nhóc Shindo Hikaru tìm thấy một bàn cờ vây cổ. Bỗng một dọng nói cất lên: \"Cậu nghe thấy tiếng ta sao?\" Chủ nhân của âm thanh ấy tên Fujiwara no Sai, vốn là Kì Thánh thời Heian, vì còn nặng lòng với cờ vây mà đã nhập vào bàn cờ để đợi 1 người có thể nghe thấy và giúp mình chơi cờ. Cuộc gặp định mệnh giữa họ đã khởi đầu cho hành trình chinh phục Nước cờ thần thánh!\nHIKARU - KÌ THỦ CỜ VÂY, tác phẩm đi cùng độc giả Việt qua bao năm tháng chính thức trở lại với ấn bản Ultimate nặng kí, chất lượng và đầy giá trị sưu tầm!! Trọn bộ 20 tập với hình thức đặc biệt, bổ sung đầy đủ tranh màu cùng những nội dung lần đầu công bố, hứa hẹn làm nức lòng bạn đọc cũ lẫn mới!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/h/i/hikaru_ki-thu-co-vay_ultimate-edition_tap-2_bia_card.jpg', 76000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(412, 'Bộ Sách Giáo Khoa Toán Singapore Lớp 2 - Workbook Mathematics 2A - More Than A Textbook', '8936037799681', '2017', 124, 52, 15, 9, 6, 'trong_nuoc', 'Bìa Mềm', 'Sách Giáo Khoa Toán Singapore Lớp 2 - Workbook Mathematics 2A - More Than A Textbook\nBộ sách được xây dưng 3 phần với 3 bộ khác nhau gồm More than a textbook Maths Textbook & Workbook Primary P1A, P1B, P2A, P2B, P3A, P3B và phần bài tập củng cố cho mỗi bộ. Mỗi bộ phù hợp với 1 lứa tuổi theo thứ thự lớp 1,2, 3.\nMore than a Textbook Maths Textbook & Workbook Primary không chỉ đơn giản là cuốn sách giáo khoa Singapore mà nó còn là một người bạn đồng hành cùng con yêu, cung cấp cho con những kỹ năng cơ bản nhất để tỏ tình thành công với toán học hiện đại. Với kết cấu rỗ ràng từng phần, bộ sách mang đến cho trẻ những kỹ năng tối quan trọng để chinh phục thành công môn toán đó là:\nKỹ năng nhận dạng toán học: Tăng khả năng tư duy dạy trẻ biết cách nhận biết những dạng toán hay gặp, những mẫu toán chung và cách thức giải quyết những dạng toán theo công thức.\nKỹ năng phân tích từng phần và tổng thể: Mỗi bài toán mẫu trong More than a textbook Maths Textbook & Workbook Primary đều được phân tích rõ ràng các bước. Mỗi phần của cuốn sarch đều được hướng dẫn cụ thể để có thể giúp trẻ giải quyết cả bài toán.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8936037799681_2.jpg', 53500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(413, 'Bộ Đạo Làm Chồng Đảm - Tập 8 - Bản Đặc Biệt - Tặng Kèm Phụ Truyện Cảnh Sát Màu Nhiệm Policure', '8935244888058', '2023', 160, 48, 4, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Một trận quyết đấu donut máu lửa, một buổi đánh golf không có hậu, một bữa cắm trại đổ mồ hôi sôi nước mắt, một cuộc tập huấn với cô cảnh sát tăng động… Những sự kiện bất thường diễn ra dồn dập đang góp phần làm nên cuộc sống rất đỗi “bình thường” của anh chàng cựu-xã-hội-đen-hoàn-lương nọ…! Và tập mới đã sẵn sàng lên kệ rồi đây!!\nKousuke Oono\nMỗi cuốn “Đạo làm Chồng đảm” bản đặc biệt tập 8 đều được tặng kèm theo một cuốn phụ truyện với chủ đề “Cảnh sát màu nhiệm Policure”! Rất nhiều người đã hỗ trợ tôi trong quá trình thực hiện nó. Xin chân thành cảm ơn các bạn!\nCâu chuyện đề tài gia đình bình thường của một người từng trong giang hồ!!\nLần đầu ra mắt BẢN ĐẶC BIỆT!! Minh họa bìa khác biệt so với bản thường!!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935244888058.jpg', 47500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(414, 'Bách Khoa Toàn Thư Cho Bé - Động Vật, Loài Cá', '8935210279026', '2021', NULL, 22, 20, 23, 6, 'trong_nuoc', 'Bìa Mềm', 'Cuốn sách giới thiệu về các loài cá, với hình ảnh sinh động, lời văn đơn giản dễ hiểu. Cuốn sách phù hợp đối tượng trẻ mầm non.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_237526.jpg', 56000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(415, 'Bộ Kính Vạn Hoa - Tập 16 - Người Giúp Việc Khác Thường - Ngủ Quên Trên Đồi - Kẻ Thần Bí (Tái Bản 2022)', '8935244864397', '2022', 376, 54, 17, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Kính Vạn Hoa - Tập 16: Người Giúp Việc Khác Thường - Ngủ Quên Trên Đồi - Kẻ Thần Bí (Tái Bản 2022)\n“Nguyễn Nhật Ánh, đó là cả một vũ trụ tuổi thơ. Từ những chuyện vặt vãnh như chơi bi, đánh nhau, trộm vặt, sợ ma, yêu đương ngây ngô,... vốn xảy ra thường nhật trong cuộc sống trẻ thơ; đến những nét văn hoá bản địa như tuồng chèo, du lịch, kinh doanh; đến văn hoá ngoại lai như mô hình kể chuyện, kiểu nhân vật, giọng kể, cốt truyện trinh thám,… đến triết học: chuyện báo ân báo oán, nguồn gốc ngôn ngữ và nguyên tắc biểu nghĩa của ngôn ngữ giữa người phát và người dịch “nghĩa”…, tất cả tạo nên trong tác phẩm của ông một thế giới ngồn ngộn chữ nghĩa và tri thức văn hoá.”\nGiáo sư LÊ HUY BẮC, Đại học Sư phạm Hà Nội\n(Nguyễn Nhật Ánh - Hiệp sĩ của tuổi thơ, Nxb Đại học Quốc gia Hà Nội, 2015)', NULL, 'https://cdn1.fahasa.com/media/catalog/product/k/i/kinh-van-hoa---phien-ban-moi---tap-16---tb-2022.jpg', 73000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(416, 'Lắng Nghe Gió Hát', '8935235238114', '2023', 192, 68, 5, 3, 6, 'trong_nuoc', 'Bìa Mềm', 'Lắng Nghe Gió Hát\nMười tám ngày của mùa hè năm hai mươi tuổi, đối với “tôi” là một kỳ nghỉ hè không sự kiện. Bất chấp những tối uống tràn ở quán Jay’s Bar cùng cậu bạn mang tên Chuột hay mối quen tình cờ với cô gái ở cửa hàng đĩa hát, thành phố quê hương ven biển mùa hè chỉ còn là gió trong “tôi”. Những chuyện kể về gió, tiếng gió hát bên bờ biển, và cảm giác tuổi thanh xuân trôi qua như gió. Mười tám ngày ấy đã gói ghém cả quá khứ, hiện tại, tương lai cùng với hoang mang, mất mát và cô đơn…\nTrong lời giới thiệu bản in tiếng Anh lần đầu tiên, Murakami nói rằng Lắng nghe gió hát và Pinball, 1973 “chiếm vị trí quan trọng trong những thành tựu” của ông, và rằng “chúng có vai trò không gì thay thế nổi, như những người bạn từ thời xưa cũ”. Vậy nhưng, tuy tác giả có dè dặt đến mấy khi đánh giá hai tác phẩm đầu tay, nhiều độc giả thủy chung của ông có thể chào đón cuốn sách như một người bạn tâm tình kinh điển, đã sớm bộc lộ những gì làm nên chất Murakami trong một hình hài xanh ngát.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935235238114.jpg', 74500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(417, 'Bộ Kính Vạn Hoa - Tập 17 - Bạn Gái - Cửa Hàng Bánh Kẹo - Một Ngày Kì Lạ (Tái Bản 2022)', '8935244864403', '2022', 328, 54, 17, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Kính Vạn Hoa - Tập 17: Bạn Gái - Cửa Hàng Bánh Kẹo - Một Ngày Kì Lạ (Tái Bản 2022)\n“Để phân tích được diễn biến “hành trình chinh phục tuổi thơ” của nhà văn Nguyễn Nhật Ánh thông qua bộ sách Kính Vạn Hoa do Nhà xuất bản Kim Đồng thực hiện, chắc chắn sẽ cần đến nhiều ý kiến của các nhà nghiên cứu. Ở đây, chúng tôi chỉ muốn nói rằng với bộ sách Kính Vạn Hoa, nhà văn Nguyễn Nhật Ánh đã nêu một minh chứng thật rõ ràng là trong sáng tạo văn chương nghệ thuật, tài năng bẩm sinh là yếu tố tối quan trọng nhưng chưa đủ, mà còn phải cần đến 99% công sức lao động. Cho đến nay, Kính Vạn Hoa đã được dựng thành phim và vẫn đang được Nhà xuất bản Kim Đồng tái bản đi tái bản lại với nhiều phiên bản. Có thể nói, bộ sách Kính Vạn Hoa là dấu mốc thành công trong thời kì đổi mới, nối dài thêm danh sách những tác phẩm văn học thiếu nhi được coi là Tủ sách vàng của Nhà xuất bản Kim Đồng trong quá trình gần 60 năm qua.”\nVŨ THỊ QUỲNH LIÊN, Tổng biên tập Nhà xuất bản Kim Đồng\n(Hội thảo khoa học “Nguyễn Nhật Ánh – Hành trình chinh phục tuổi thơ” ngày 16-9-2015 tại Đại học Sư phạm Hà Nội)', NULL, 'https://cdn1.fahasa.com/media/catalog/product/k/i/kinh-van-hoa---phien-ban-moi---tap-17---tb-2022.jpg', 73000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(418, 'Bộ Trong Công Sở, Ngoài Đời Tư - On & Off - Tập 1 - Bản Sưu Tầm - Tặng Kèm Bookmark Nhựa Trong + Huy Hiệu Kim Loại + Lenticular Card + Set Keychain Switch + Thẻ Staff', '8935250716130', '2025', 138, 50, 8, 11, 6, 'trong_nuoc', 'Bìa Mềm', 'Trong Công Sở, Ngoài Đời Tư - On & Off - Tập 1\nAi đi làm cũng có lúc ON nơi công sở và OFF lúc riêng tư.\nCó người là nam nhân viên công ty, ra ngoài lại mặc đồ lolita như một cô gái.\nCó người là nữ nhân viên công ty, xong việc lại vận đồ punk rất đàn ông.\nĐây là tập 2 câu chuyện thường nhật về khả năng “biến hình” của hai nhân viên công ty với khác biệt giữa hai trạng thái ON và OFF khiến bạn đọc không khỏi rung rinh!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/1/8/180425-6.jpg', 247000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(419, 'Tái Tạo Tổ Chức (Tái Bản 2020)', '8935278600930', '2020', 208, 56, 15, 20, 6, 'trong_nuoc', 'Bìa Mềm', 'Chỉ trong vòng một thế kỷ, những triết lý kinh doanh của Henry Ford đã tạo nên một nền công nghiệp sản xuất hàng hóa và dịch vụ phát triển rực rỡ trên toàn cầu, ảnh hưởng sâu sắc đến các tổ chức và mỗi cá nhân.\nTuy nhiên, thế giới quen thuộc ngày nay đang dần chết đi. Một thế giới mới đang mở ra. Cách mạng công nghiệp mới, năng lượng tái tạo, biến đổi khí hậu, toàn cầu hóa, trí thông minh nhân tạo, thực tế ảo… tất cả đều phát triển nhanh đến chóng mặt. Vì vậy, con người không còn lựa chọn nào khác ngoài việc tái sắp xếp cách tổ chức của họ nhằm đáp ứng với những thách thức của thiên niên kỷ thứ ba. Giữa cuộc giao thời này, quan niệm của chúng ta trong công việc cũng thực sự biến đổi.\nĐó là lí do chúng tôi tìm đến Tái tạo tổ chức – một cuốn sách thôi thúc chúng ta khám phá bản thân để đạt được hạnh phúc chân chính bằng cách tạo ra các mối quan hệ đích thực xung quanh mình. “Đích thực” ở đây có nghĩa là những mối quan hệ được tạo ra từ sự thấu hiểu, tin tưởng, lòng nhân ái trên nền tảng minh bạch và cân bằng. Bởi tính chủ động, phong phú và chân thành của chúng, những mối quan hệ này đôi lúc khiến ta bị tổn thương, nhưng qua những tổn thương tích cực đó, chúng ta sẽ nhanh chóng trưởng thành, sẽ cảm thấy rằng mình thực sự sống.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_29799.jpg', 152000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(420, 'Bộ Luyện Viết Chữ Đẹp Từ Vựng Tiếng Anh Family And Friends - National Edition 2', '8936214270590', '2023', 44, 69, 9, 25, 6, 'trong_nuoc', 'Bìa Mềm', 'Luyện Viết Chữ Đẹp Từ Vựng Tiếng Anh Family And Friends - National Edition 2 được biên soạn nội dung theo giáo trình Family and Friends dành cho các bé học sinh từ lớp 1 đến lớp 3, hỗ trợ các bé học hiệu quả, ghi nhớ nhanh từ vựng.\nThiết kế với nhiều hình ảnh minh họa dễ thương, sinh động. Thu hút sự tập trung cũng như tạo được hứng thú cho con học tập. Tăng hiệu quả học tập nhờ việc vừa tập viết vừa ghi nhớ nhanh nhờ tư duy hình ảnh. Tạo điều kiện để bố mẹ dễ dàng kèm con học nhờ các hoạt động khuyến khích con chủ động đoán nghĩa từ vựng thông qua hình ảnh.\nCác chủ đề, chủ điểm từ vựng trong sách cũng chính là các chủ để cơ bản và thường gặp với đời sống thường ngày. Bởi vậy, việc ghi nhớ bộ từ vựng này cũng sẽ giúp con tăng cường vốn từ vựng phong phú để ứng dụng trong giao tiếp hàng ngày.\nKèm sau mỗi bài học là những hoạt động thực hành thú vị, các con vừa được ôn lại từ vựng hiệu quả, vừa được thoải mái thư giãn. Phần đáp án chi tiết và trình bày dễ hiểu dễ dàng cho con đối chiếu, đánh giá, tự chấm điểm bản thân, rèn luyện kĩ năng tự học ngay từ bé.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8936214270590.jpg', 29500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(421, 'Bộ Chuẩn Bị Cho Bé Vào Lớp 1 - Em Tập Ghép Vần - Quyển 6 (Tái Bản 2020)', '8935095629596', '2020', 32, 59, 20, 4, 6, 'trong_nuoc', 'Bìa Mềm', 'Bộ sách chuẩn bị cho bé vào lớp 1 với những hình minh họa sinh động phù hợp để cha mẹ hướng dẫn bé làm quen với chữ cái, chữ số.\nCha mẹ và các em hãy đón mua!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_32299.jpg', 13500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(422, 'Khát Vọng Sống (Bìa Mềm)', '8936071677167', '2020', 496, 53, 16, 8, 6, 'trong_nuoc', 'Bìa Mềm', 'Thuật lại quãng đời ngắn ngủi nhưng rực cháy đam mê của Van Gogh, Khát vọng sống được xem là tiểu thuyết tiểu sử thành công nhất về cuộc đời các danh nhân. Tác giả của nó, Irving Stone, vốn là nhà viết kịch, khi lần đầu xem tranh của Van Gogh tại Paris đã gặp phải một trải nghiệm chưa từng có và quyết định viết một cuốn sách về danh họa này “nếu không, sẽ chẳng viết gì khác”. Để thực hiện mong muốn, Stone quay về New York viết báo và dành dụm nhuận bút để lần theo dấu chân của người họa sĩ qua các vùng đất tại Anh, Hà Lan, Bỉ, Pháp, gặp gỡ nhiều người và nghiên cứu hơn 650 thư từ giữa Van Gogh và người em, Theo Van Gogh. Năm 1934, tác phẩm ra đời và lập tức lọt vào danh sách bán chạy. Gây xúc động sâu sắc bởi nỗi cô đơn cùng cực, những khát vọng cùng cực với nghệ thuật, tình yêu và cuộc sống, tác phẩm đã góp phần làm nên danh tiếng bất tử của Van Gogh, người bấy giờ vẫn còn ít được biết đến tại Hoa Kỳ cũng như trên thế giới.\nThông tin tác giả: Irving Stone (1903 - 1989)\nIrving Stone là nhà văn Mỹ được vinh danh như bậc thầy của lĩnh vực tiểu thuyết tiểu sử. Năm 22 tuổi, ông bỏ dở việc học tiến sĩ kinh tế để theo đuổi đam mê viết lách từ thuở thiếu thời. Ban đầu ông thử sức ở mảng sáng tác kịch nhưng không gặt hái thành công, chỉ đến khi (Lust for Life, 1934) ra mắt, tên tuổi ông mới đến với công chúng.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_26263.jpg', 156000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11');
INSERT INTO `sach` (`id`, `tieu_de`, `isbn`, `nam_xuat_ban`, `so_trang`, `tac_gia_id`, `nha_xuat_ban_id`, `nha_cung_cap_id`, `the_loai_id`, `loai_sach`, `hinh_thuc_bia`, `mo_ta`, `file_anh_bia`, `link_anh_bia`, `gia_ban`, `gia_goc`, `so_luong_ton`, `created_at`, `updated_at`) VALUES
(423, 'Tủ Sách Bé Vào Lớp Một - Bé Tập Tô Và Làm Quen Với Chữ Số (Tái Bản 2019)', '8936067601275', '2019', 23, 64, 20, 5, 6, 'trong_nuoc', 'Bìa Mềm', 'Tủ Sách Bé Vào Lớp Một - Bé Tập Tô Và Làm Quen Với Chữ Số (Tái Bản 2019)', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_6508.jpg', 8470.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(424, 'Bộ Các Vị Thần Của Đỉnh Olympus - Phần 4: Ngôi Nhà Của Thần Hades (Tái Bản 2021)', '9786043202755', '2021', 615, 55, 18, 19, 6, 'trong_nuoc', 'Bìa Mềm', 'Ở cái kết cuốn Dấu Hiệu Athena, Annabeth và Percy đã bị sụt xuống một cái hố dẫn thẳng Tartarus. Năm á thần còn lại phải dẹp nỗi đau của họ, làm theo hướng dẫn của Percy để tìm đường tới Cửa Tử. Nếu họ có thể chiến đấu chống lại được đội quân của Gae, Percy cùng Annabeth có thể sống sót ở Ngôi Nhà của Thần Hades thì bảy á thần có thể niêm phong được Cửa Tử từ cả hai phía và ngăn chặn được sự tiếp sức của Gae cho bọn khổng lồ. Nhưng Leo lo ngại rằng nếu đóng Cửa Tử, làm sao Percy và Annabeth có thể thoát ra?', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_225997.jpg', 199000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(425, 'Năng Lượng Sống Từ Thảo Dược', '8935095628957', NULL, 436, 60, 21, 4, 6, 'trong_nuoc', 'Bìa Cứng', 'Các bạn có biết ngay trong căn bếp nhà mình có cả một rương thuốc thảo dược rất tốt chăng?\nNĂNG LƯỢNG SỐNG TỪ THẢO DƯỢC sẽ chỉ cho bạn cách làm thế nào để chuyển hóa các loại nguyên liệu thông thường thành thức ăn và dược liệu chữa bệnh. Qua hướng dẫn của dược sư Rosalee de la Forêt, bạn sẽ hiểu được cách làm thế nào để khớp các đặc tính của từng loại cây với nhu cầu của chính cơ thể mình, để có một cách tiếp cận cụ thể dành cho sức khỏe của cá nhân bạn và gia đình.\nHãy nuôi dưỡng hiểu biết về các loại gia vị cùng thảo dược và bắt đầu sử dụng các dược liệu từ thiên nhiên để nấu ăn, chữa lành và chăm sóc cả gia đình bạn!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/u/n/untitled-1_1.gif', 260000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(426, 'Cuốn Sách Lớn Đầu Tiên Của Tớ - Vũ Trụ (Tái Bản 2023)', '8935244887228', '2023', 128, 63, 4, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Cuốn Sách Lớn Đầu Tiên Của Tớ: Vũ Trụ\nThế giới có muôn vàn điều kì thú và bộ sách Cuốn Sách Lớn Đầu Tiên của Tớ sẽ dẫn bé bước vào cuộc hành trình khám phá thế giới diệu kì ấy.\nTập sách Vũ Trụ với những minh họa ảnh đẹp và sống động, giúp các bạn nhỏ làm quen với vũ trụ bao la, không chỉ các hành tinh trong hệ mặt trời mà còn cả những nơi xa xôi hơn nữa như: hố đen, các tinh vân…\nTrong sách các em sẽ tìm thấy:\n- Hơn 100 hình mô phỏng vũ trụ và các bức ảnh tuyệt đẹp.\n- Tin tức mới nhất về công cuộc chinh phục vũ trụ.\n- Các câu chữ thật đơn giản cho việc đọc với những em mới tập đọc, và trong mỗi trang sách đều có các ví dụ minh họa thực tế vui nhộn.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/c/u/cuon-sach-lon-dau-tien-cua-to_bia_vu-tru_tb-2023.jpg', 135000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(427, 'Ruột Ơi Là Ruột - Bí Mật Của Thế Giới Bị Lãng Quên', '8935235239142', '2023', 349, 49, 7, 3, 6, 'trong_nuoc', 'Bìa Mềm', 'Ruột Ơi Là Ruột - Bí Mật Của Thế Giới Bị Lãng Quên\nRuột ơi là ruột mời gọi chúng ta khám phá một trong những cơ quan phức tạp nhất, quan trọng nhất và có thể nói là diệu kỳ nhất trong cơ thể, nơi cư trú của cả một thế giới sống động – với số lượng đông đảo gấp nhiều lần loài người cư ngụ trên Trái đất gồm các chiến binh tí hon của hệ miễn dịch và vô vàn quần thể vi sinh vật có lợi đang tích cực làm việc để nuôi sống và bảo vệ chúng ta: đường ruột. Qua cuộc hành trình của miếng bánh đi từ miệng, thực quản, dạ dày xuống ruột non, ruột già rồi dừng chân ở một luống rau nào đó, cùng những hình ảnh minh họa ngộ nghĩnh và ví dụ gần gũi, cuốn sách cung cấp những thông tin hữu ích về quá trình hấp thụ chất dinh dưỡng, tầm quan trọng của vi khuẩn tốt với trẻ sơ sinh, mối liên hệ của hệ vi khuẩn đường ruột với các chứng bệnh, từ chứng bất dung nạp, chứng dị ứng, cho đến các chứng bệnh kỳ lạ mà ta tưởng chừng chẳng hề có liên quan như chứng căng thẳng, bệnh Alzheimer và cả hiện tượng tự sát...\nCuốn sách chắc làm thay đổi thói quen ăn uống và sinh hoạt của chúng ta, để có một đường ruột khỏe mạnh, bởi “đường ruột khỏe, cơ thể mạnh”.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935235239142.jpg', 95000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(428, 'Bộ Dụng Cụ Học Sinh Kuromi - iiGEN EN880630 (160 Chi Tiết)', '8886312601577', NULL, NULL, NULL, NULL, NULL, 6, 'trong_nuoc', NULL, 'Bộ Dụng Cụ Học Sinh Kuromi - iiGEN EN880630 (160 Chi Tiết)\nBộ sản phẩm được đựng trong một chiếc vali có quai xách tiện lợi, dễ dàng mang đi khắp nơi, tại nhà hay đến trường.\nGiúp trẻ phát huy khả năng sáng tạo, nhận biết màu sắc, phối hợp tay mắt và kỹ năng vận động.\nBộ dụng cụ vẽ với đầy đủ các dụng cụ cho các bé thích tô màu, vẽ tranh…\nBộ sản phẩm rất thích hợp dùng làm quà tặng cho trẻ, giúp bé có thể vừa chơi vừa học, kích thích sự sáng tạo của bé.\nSản phẩm gồm :\n- 16 màu sơn nước\n- 12 bút lông màu nước 2 đầu', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/8/8886312601577.jpg', 690000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(429, 'Đường Trần - Ngọn Lửa Không Bao Giờ Tắt (Tái Bản 2022)', '8934974182641', '2022', 448, 66, 22, 24, 6, 'trong_nuoc', 'Bìa Mềm', 'Tôi thấy cần phải viết một cuốn sách về đời mình.\nViết để ghi lại những năm tháng đã qua, không tiếc nuối quá khứ, để sống thanh thản những năm tháng Bà Trần Tố Nga, người đứng tên kiện các công ty hóa chất Mỹ với tư cách là nạn nhân da cam, bà viết để khẳng định rằng trong tất cả những cuộc chiến đấu và công việc đã trải qua, tôi luôn theo đuổi một mục tiêu: Hạnh phúc của những người khổ hơn tôi, Công lý cho nhân dân tôi, Hòa bình và Hữu nghị cho tất cả. Đó cũng là tất cả những gì ông bà, cha mẹ đã để lại cho tôi.\nĐường Trần được khởi đầu  trong một chiều mưa thu Paris như vậy.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8934974182641.jpg', 123000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(430, 'Mẹ Ơi, Mình Cùng Làm Nhé!', '8935244870428', '2022', 28, 70, 17, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Mẹ Ơi, Mình Cùng Làm Nhé!\nTác gia người Mĩ chuyên viết cho thiếu nhi - Kate Douglas Wiggin - từng nói: “Trên đời này, hầu hết những gì đẹp đẽ đều hiện ra thành đôi, thành ba, thành hàng tá hay hàng trăm... nhiều như thể những bông hồng, những buổi hoàng hôn, những vầng cầu vồng… nhưng ai cũng chỉ có một người mẹ mà thôi.”\nThật vậy, sự âu yếm của mẹ, cuộc dạo chơi thú vị, những giây phút say sưa nghe kể chuyện vui tươi… sẽ theo bé đi suốt cuộc đời.\nHãy cùng lật giở từng trang sách tuyệt đẹp và đáng yêu để khám phá tình cảm ấm áp của bé và mẹ nhé!\nTác giả Ngô Anh Thi (sinh năm 1979) hiện đang sống cùng gia đình nhỏ tại Hà Lan. Chị từng tham gia dịch một số tác phẩm văn học thiếu nhi của Hà Lan, tiêu biểu là truyện Bà tôi đã từ từ nhỏ đi và Bạn chính là sản phẩm của Não…', NULL, 'https://cdn1.fahasa.com/media/catalog/product/m/e/me-oi-minh-cung-lam-nhe-1.jpg', 27000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(431, 'Bộ Sách Bé Tự Tin Bước Vào Lớp 1: Dành Cho Bé Từ: 5-6 Tuổi (Bộ 9 Cuốn)', '8935210250858', '2020', NULL, 71, 20, 23, 6, 'trong_nuoc', 'Bìa Mềm', 'Bộ Sách Bé Tự Tin Bước Vào Lớp 1: Dành Cho Bé Từ: 5-6 Tuổi (Bộ 9 Cuốn)\nNội dung mỗi cuốn sách giúp bé rèn luyện những kĩ năng khác nhau như làm quen với chữ số, chữ cái, ghép vần, học đọc, học đếm… Với kiến thức mới mẻ, hình vẽ sinh động sẽ khiến trẻ cảm thấy hứng thú và học tập dễ dàng hơn.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_235821.jpg', 91500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(432, 'Ăn Bẩn Sống Lâu', '8935095626786', '2018', 490, 51, 14, 4, 6, 'trong_nuoc', 'Bìa Mềm', 'Ăn Bẩn Sống Lâu\nTrong khi tất cả chúng ta đang hướng đến ăn sạch, ở sạch thì Josh Axe lại khuyến khích người ta hãy ăn bẩn.\nTheo Josh Axe, việc ăn sạch, ở sạch là tốt nhưng nếu chúng ta vận dụng nó một cách cực đoan tự biến môi trường sống của mình trở nên vô trùng thì điều đó rất nguy hiểm đối với hệ miễn dịch của chúng ta. Vô hình trung bạn đã tiêu diệt những vi trùng có khả năng đóng vai trò miễn dịch tự nhiên trong cơ thể, bạn không còn khả năng tự bảo vệ và chữa lành cho cơ thể trước những tổn thương.\nĐừng ngại những vết bẩn nhỏ mà nên chủ động hòa theo nhịp điệu tự nhiên và hấp thu năng lượng chữa lành tồn tại quanh ta từng ngày đó là những điều khởi thảo cho việc Ăn bẩn sống lâu.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/a/n/an-ban-song-lau.x.b.jpg', 116000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(433, 'Câu Chuyện Nghệ Thuật - The Story Of Art', '8935270703417', '2022', 692, 58, 14, 21, 6, 'trong_nuoc', 'Bìa Cứng', 'Câu Chuyện Nghệ Thuật - The Story Of Art\n“The Story of Art\" (Câu Chuyện Nghệ Thuật) được in lần đầu năm 1950 và trong 70 năm qua, được dịch ra gần 30 thứ tiếng và hơn tám triệu bản đã được bán ra trên toàn thế giới. Điều đó khiến tác phẩm trở thành cuốn sách nghệ thuật bán chạy nhất mọi thời đại và là tác phẩm nhập môn nghệ thuật thị giác cho vô số thế hệ độc giả.\nTác giả E.H Gombrich (1909-2001) là một trong những nhà sử học nghệ thuật lỗi lạc nhất của nửa sau thế kỷ 20, đối với giới hàn lâm cũng như với tầng lớp công chúng rộng rãi. Những tác phẩm khác mang tính lý thuyết của ông cũng đã trở thành những công trình then chốt đối với các nhà nghiên cứu lịch sử nghệ thuật.\nCâu Chuyện Nghệ Thuật là một tác phẩm kể về lịch sử nghệ thuật châu Âu từ thời cổ đại đến hiện đại, được tác giả khảo sát và đánh giá trong các lĩnh vực khác nhau như hội họa, điêu khắc, kiến trúc… song hành với những chuyển biến và giao thoa của các nền văn hóa, chính trị, và tôn giáo. Nguồn tư liệu phong phú về các tác phẩm đáng chú ý, những tên tuổi tài năng, những trường phái, phong cách đặc sắc trong dòng chảy nghệ thuật.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935270703417.jpg', 1019000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(434, 'Nơi Ánh Sáng Không Bao Giờ Tắt', '8935280908475', '2021', 264, 92, 24, 9, 6, 'trong_nuoc', 'Bìa Mềm', 'Trong dòng chảy sống động của nghề y, ở nơi người ta cứ ngỡ sẽ chỉ thấy những giọt nước mắt lăn dài nhưng cũng có thể tìm thấy những nụ cười hạnh phúc, tìm thấy biết bao câu chuyện nghị lực của bác sĩ - bệnh nhân trên hành trình tìm lại sự sống. “ Nơi ánh sáng không bao giờ tắt” là những câu chuyện nghề, chuyện đời qua lăng kính của một bác sĩ, được viết với văn phong gần gũi, giản dị mang đến cho chúng ta nhiều bài học về cách trân trọng cuộc sống.\nBác sĩ Trần Quốc Khánh hiện đang là phẫu thuật viên chuyên ngành thần kinh cột sống tại bệnh viện Hữu nghị Việt - Đức. Anh sinh ra tại vùng núi rừng tại xã Thanh Đức, huyện Thanh Chương, Nghệ An, một xã rẻo cao, giáp với biên giới nước bạn Lào. Ở nơi một vùng cao xa xôi, hiểm trở, xa cha mẹ từ năm 8 tuổi nhưng ý chí và niềm đam mê học tập trong bác sĩ Khánh chưa bao giờ chùn bước. Với suy nghĩ phải nỗ lực học tập mới có thể thay đổi tương lai, sau nhiều năm cố gắng, bác sĩ Khánh được tuyển thẳng vào Đại học Y Hà Nội và hiện đang làm việc tại bệnh viện Hữu nghị Việt - Đức.\nTrong cuốn sách “Nơi ánh sáng không bao giờ tắt” của mình, bác sĩ Khánh đã ghi chép lại những khó khăn anh đã trải qua thời thơ ấu cùng những sự kiện trong cuộc đời đã đưa anh tới quyết định trở thành một bác sĩ tận tâm và giàu tình yêu thương với bệnh nhân. Nhiều năm theo đuổi nghề Y, với bác sĩ Khánh, việc trở thành một bác sĩ không chỉ là lý tưởng của bản thân mà còn là vì trách nhiệm với ngành nghề mình đã chọn lựa.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_236466.jpg', 126500.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(435, 'Mẹ Là Của Tớ', '8935244870411', '2022', 32, 70, 17, 6, 6, 'trong_nuoc', 'Bìa Mềm', 'Mẹ Là Của Tớ\nTác gia người Mĩ chuyên viết cho thiếu nhi - Kate Douglas Wiggin - từng nói: “Trên đời này, hầu hết những gì đẹp đẽ đều hiện ra thành đôi, thành ba, thành hàng tá hay hàng trăm... nhiều như thể những bông hồng, những buổi hoàng hôn, những vầng cầu vồng… nhưng ai cũng chỉ có một người mẹ mà thôi.”\nThật vậy, sự âu yếm của mẹ, cuộc dạo chơi thú vị, những giây phút say sưa nghe kể chuyện vui tươi… sẽ theo bé đi suốt cuộc đời.\nHãy cùng lật giở từng trang sách tuyệt đẹp và đáng yêu để khám phá tình cảm ấm áp của bé và mẹ nhé!\nTác giả Ngô Anh Thi (sinh năm 1979) hiện đang sống cùng gia đình nhỏ tại Hà Lan. Chị từng tham gia dịch một số tác phẩm văn học thiếu nhi của Hà Lan, tiêu biểu là truyện Bà tôi đã từ từ nhỏ đi và Bạn chính là sản phẩm của Não…', NULL, 'https://cdn1.fahasa.com/media/catalog/product/m/e/me-la-cua-to-1.jpg', 27000.00, NULL, 20, '2026-03-10 11:24:11', '2026-03-10 11:24:11'),
(436, 'Phía Không Nhau', '9786326043341', '2025', 111, 75, 7, NULL, 10, 'trong_nuoc', 'Bìa Mềm', 'Phía Không Nhau\nCuốn sách là tập thơ – tản văn chứa đựng những nỗi niềm sâu lắng về tình yêu, sự chia xa và những khoảng trống trong tâm hồn. Với giọng văn tinh tế, mộc mạc mà day dứt, Hannah Hoang đưa người đọc đi qua những mùa nhớ, những...', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/7/9786326043341.jpg', 76500.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(437, 'Thơ Viết Cho Con - A Poem For My Child', '9786326232707', '2025', 64, 76, 10, NULL, 10, 'trong_nuoc', 'Bìa Mềm', 'Thơ Viết Cho Con - A Poem For My Child\nThơ viết cho con, ghi lại từng khoảnh khắc yêu thương, từng dấu mốc trưởng thành của con qua năm tháng. Mỗi vần thơ chứa đựng nỗi niềm mong mỏi, là ánh mắt dõi theo, là vòng tay bao bọc của mẹ trong suốt hành trình con lớn lên.\nTác giả Đinh Thị Cẩm Hà hiện là Tiến sĩ giảng viên luật tại một trường đại học ở phía Nam. Dù không phải là cây viết chuyên nghiệp, nhưng tác giả rất yêu thơ, xem việc viết thơ như một cách để đối thoại với chính mình và lưu giữ những cảm xúc hằng ngày.\nTập thơ “Thơ viết cho con” là tuyển tập đầu tay của tác giả được viết từ góc nhìn của một người mẹ. Qua những vần thơ mộc mạc, giản dị, tác giả không chỉ ghi lại những cảm xúc, những quan sát trong hành trình làm mẹ của riêng mình, mà còn thể hiện cảm xúc chung của những người mẹ đã, đang và sẽ đi qua những tháng năm nuôi con bằng tất cả tình yêu thương gia đình vô điều kiện.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/7/9786326232707.jpg', 88200.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(438, 'Mượn Vần Thơ Tỏ Vần Thương - Ước Gì Anh Được Yêu Đương Với Nàng', '8935325034497', '2026', 160, 77, 1, 10, 10, 'trong_nuoc', 'Bìa Mềm', 'Mượn Vần Thơ Tỏ Vần Thương - Ước Gì Anh Được Yêu Đương Với Nàng\n“Si mê cũng bởi ngọt ngào\nCậu không thả thính đời nào được yêu\nSách này mách cậu lắm chiêu\nThả đâu trúng đấy, nói điêu làm gì.”\nĐây chính là lời chào đầu của cuốn sách mang tên “Mượn vần thơ, tỏ vần thương” của tác giả Cừu Văn Vở. Chủ đề xuyên suốt của tập thơ này là tình yêu - tưởng sẽ rất cũ nhưng lại mới không tưởng nhờ những câu thơ thơ lục bát mang âm hưởng dân gian pha trộn ngôn từ trẻ trung bắt nhịp cùng GenZ. Cuốn sách này sẽ cùng bạn “chơi chữ” vừa tình vừa hài:\n“Ngày Tết phải có bánh chưng', NULL, 'https://cdn1.fahasa.com/media/catalog/product/_/m/_m_n-v_n-th_-t_-v_n-th_ng_---b_a-1.jpg', 71000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(439, 'Truyện Kiều (Tái Bản 2026)', '8936238101580', '2026', 248, 78, 1, 5, 10, 'trong_nuoc', 'Bìa Mềm', 'Truyện Kiều\nQuyển Truyện Thúy Kiều này là một quyển sách kiệt tác làm bằng quốc âm ta. Người trong nước từ kẻ ngu phu ngu phụ cho chí người có văn học, ai cũng biết, ai cũng đọc, mà ai cũng chịu là hay. Một quyển sách có giá trị như thế, mà chỉ hiềm vì các bản in ra, có nhiều bản không giống nhau, rồi có người lại tự ý mình đem chữa đi, chữa lại, thành ra càng ngày càng sai lầm thêm ra. Mới đây những bản in bằng quốc ngữ, tuy có dễ đọc và dễ xem hơn trước, nhưng chưa thấy có bản in nào thật chính đáng, những điều sai lầm vẫn còn như các bản chữ Nôm cũ, mà chữ quốc ngữ viết lại không được đúng, và những lời giải thích cũng không kỹ càng lắm. Chúng tôi thấy vậy, mới nhặt nhạnh các bản cũ, rồi so sánh với các bản mới để hiệu chỉnh lại cho gần được như nguyên văn. Chúng tôi lại hết sức tìm tòi đủ các điển tích mà giải thích cho rõ ràng, để ai xem cũng hiểu, không phải ngờ điều gì nữa.Hiện nay tập nguyên văn của tác giả làm ra thì không tìm thấy nữa, chỉ có hai bản khác nhau ít nhiều là: bản Phường in ở phố Hàng Gai, Hà Nội; và bản Kinh của vua Dực Tông bản triều đã chữa lại.Bản Phường là bản của ông Phạm Quý Thích đem khắc, in ra trước hết cả.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8936067604634_1.jpg', 51000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(440, 'Thơ', '8935235247284', '2026', 503, 79, 5, 3, 10, 'trong_nuoc', 'Bìa Mềm', 'Thơ\nQuý độc giả thân mến!\nTháng 2 năm 2008, chưa đầy ba năm sau khi thành lập (2005), Nhã Nam đã ấn hành tác phẩm Trần Dần - Thơ. Ở thời điểm đó, Trần Dần (1926-1997) và những trước tác phẩm của ông vẫn còn khá “bí ẩn” dù một số tác phẩm đơn lẻ của ông đã được xuất bản vào đầu thập niên 1990 và các câu chuyện gần như huyền thoại về ông vẫn được kể đây đó. Những gì thực sự là Trần Dần, những bản thảo, tác phẩm sáng giá nhất của Trần Dần vẫn chưa được công bố, và do đó, phần nhiều độc giả vẫn chỉ biết đến ông với danh xưng thi sĩ đúng nghĩa nhất của từ này. Trần Dần – Thơ, vì thế, như một tuyển chọn bước đầu nhằm cung cấp cho độc giả cơ hội đọc thơ Trần Dần, từ đó, có thể cảm nhận, đánh giá thơ ông một cách khách quan, kỹ lưỡng hơn. Dĩ nhiên, thơ Trần Dần và thành tựu cách tân thơ của ông không dễ dàng nhận định, tổng kết trong dăm câu ba điều vội vàng.\nTrần Dần – Thơ lựa chọn, sắp xếp các tác phẩm theo hành trình sáng tác của Trần Dần, bắt đầu mốc năm 1955, trải qua những năm 1960 – 1970, rồi dừng lại cuối thập niên 1980. Tập thơ cũng chọn in “Dạ Đài, tuyên ngôn tượng trưng” và hai bài thơ đầu tay, nghĩa là thời điểm Trần Dần bước vào thi đàn, 19 tuổi, lập nhóm thơ tượng trưng cùng Trần Mai Châu, Đinh Hùng, Vũ Hoàng Địch, Vũ Hoàng Chương. Theo trục thời gian trong Trần Dần – Thơ, độc giả có thể nhìn thấy những bước đường tìm tòi, thử nghiệm viết, sự quyết liệt từ chối cái cũ, cái quen thuộc, nỗ lực phá vỡ các khuôn mẫu, làm mới chính mình của Trần Dần. Từ thơ tượng trưng đến kiểu thơ bậc thang, từ biến tấu âm và biến tấu chữ như một thực hành nghệ thuật ý niệm, từ lời đến không lời, từ thơ-bè đến thơ mini,… Trần Dần chưa bao giờ ngơi nghỉ ý tưởng, không ngừng tìm kiếm và phát hiện các chân trời của sáng tạo thơ. Trần Dần tự thu hẹp mình, đẩy công cuộc làm thơ vào các thử thách khó khăn nhất và đồng thời cũng tự mở rộng tối đa nhất, tự do nhất các khả năng biểu đạt, tồn tại của thơ. Trần Dần dường như không xác quyết mục tiêu cuối cùng, một đích đến lý tưởng duy nhất, ngoại trừ, luôn luôn định hình mình là một cá nhân, một tâm thế đơn độc nhất, một kẻ tiên ngoại cuộc tiên phong nhất, một “ngôi sao lủi thủi góc trời” trong bối cảnh văn hóa, văn học không cho ai cơ hội được trở thành như thế.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935235247284.jpg', 237000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(441, 'Thơ - Bìa Cứng', '8935235246393', '2026', 424, 80, 5, 3, 10, 'trong_nuoc', 'Bìa Cứng', 'Thơ\n“Xây dựng thế giới nhân vật không phải là công việc nhất thiết của một thi sĩ trữ tình. Điều căn bản là bộc lộ cái tôi của mình. Tuy nhiên, cái tôi ấy chỉ thực sự được phơi trải khi gặp đối tượng của nó. Cho nên nhân vật trong thơ trữ tình vừa là đối tượng khách thể vừa như những đối ảnh, những hóa thân, hiện thân khác nhau của cái tôi thi sĩ. Cái thế giới mà Nguyễn Duy dựng lên suốt cả nghiệp thơ của mình, hoàn toàn có thể coi là cõi chúng sinh thì hiện tại: binh lửa và bụi bặm, bùn nước và gió trăng, nghèo đói và tiềm năng, tàn phá và gây dựng, xơ xác và nhen nhóm, bần bách và phù hoa… mà đâu đâu cũng là mồ hôi và nước mắt. Có ngẫu nhiên đâu, khi ở đó, nhân loại nhân vật của thi sĩ này hầu hết là thảo dân! Họ là thập loại chúng sinh thì hiện tại.”', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935235246393.jpg', 339000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(442, 'Những Bông Hoa Không Chết', '9786042258562', '2026', 240, 81, 4, 6, 10, 'trong_nuoc', 'Bìa Mềm', 'Những Bông Hoa Không Chết\nLưu Quang Vũ – Xuân Quỳnh và thơ…\nMột bên như những chiêm nghiệm, trăn trở trước cuộc đời và thân phận con người…\nMột bên là lời tâm tình chân thành, nồng hậu của người phụ nữ khát khao hạnh phúc, hết lòng trong tình yêu đôi lứa, gia đình, nhân gian…\nVới Lời kể chuyện của Lưu Khánh Thơ\nNHỮNG BÔNG HOA KHÔNG CHẾT mở ra không gian nghệ thuật giàu chất thơ, đậm chất đời, nuôi dưỡng tâm hồn người đọc trong niềm tin vào vẻ đẹp của Tình Yêu và Thiện Lương.\n---\n“Những bạn bè đã chết', NULL, 'https://cdn1.fahasa.com/media/catalog/product/n/h/nhung-bong-hoa-khong-chet_bia.jpg', 67500.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(443, 'Ký Ức Miền Quê', '9786320401086', '2025', 100, 82, 5, NULL, 10, 'trong_nuoc', 'Bìa Mềm', 'Ký Ức Miền Quê\nNguyễn Cảnh là cây bút mới, xuất thân từ gia đình nông dân và sinh ra, lớn lên tại miền quê còn nghèo khó tại xã Mỹ Tú. Khi lên học phổ thông, tác giả đã có niềm đam mê với các môn xã hội, nhất là môn ngữ văn. Với tinh thần cầu tiến, học tập, tác giả đã trúng tuyển đại học với số điểm cao nhất, trở thành thủ khoa khối C, Trường Đại học Cần Thơ vào năm 2009.\nSau khi tốt nghiệp, tác giả vào công tác tại Ban Tổ chức Tỉnh ủy Sóc Trăng cũ và nay là Ban Tổ chức Thành ủy Cần Thơ. Trong quá trình công tác, tác giả vẫn thường làm thơ, sáng tác các tác phẩm, gửi cộng tác cho cơ quan báo chí. Trong đó, có nhiều bài thơ được đăng trên Tạp chí Văn nghệ Sóc Trăng, các trang báo Xuân của Hội đồng nhân dân tỉnh, Ban Tuyên giáo Tỉnh ủy Sóc Trăng và các ấn phẩm khác. Đặc biệt, tác giả đã đạt giải Khuyến khích Cuộc thi thơ “Sóc Trăng trong tôi” vào năm 2023 do Hội Văn học và Nghệ thuật tỉnh Sóc Trăng (cũ) tổ chức.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/7/9786320401086_1.jpg', 79000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(444, 'Nghìn Nghi Lễ Tình', '8936144202821', '2026', 112, 83, 10, 26, 10, 'trong_nuoc', 'Bìa Mềm', 'Nghìn Nghi Lễ Tình\nNhững dòng thơ buông nhẹ, đạm mà sâu, khó lần ra mấu nối, bởi chúng không theo một logic tự sự hay trữ tình thông thường: có thể gọi đó là chất phiêu của ngôn ngữ thơ ca. Nhật Chiêu giỏi trong biểu đạt cái hỗn mang vô thường ảo diệu của thế giới và của lòng người. Mọc lên từ thổ nhưỡng Việt, thơ ông là lá cành của trầm tư triết học phương Đông, và hoa trái trổ ra ở đó nhờ một tâm hồn thấu cảm.\n_ Nguyễn Thị Thanh Xuân\n_____________________\nNHẬT CHIÊU - Tác giả của biên khảo Ba nghìn thế giới thơm và các tập truyện ngắn: Người ăn gió và quả chuông bay đi, Lời tiên tri của giọt sương, Mưa mặt nạ, Viết tên trên nước, Ân ái với hư không cùng hai tập thơ Tôi là một kẻ khác và Nghìn nghi lễ tình.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/z/7/z7380479750911_4035a2ba5a63cc430c2bda7527a47636_120d971cb62146cca4008fa583eb6854_1024x1024.jpg', 78000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(445, 'Kim Vân Kiều', '8935235247437', '2026', 227, 84, 5, 3, 10, 'trong_nuoc', 'Bìa Mềm', 'Kim Vân Kiều\n“Trời còn để có hôm nay, Tan sương đầu ngõ, vén mây giữa trời; Hoa tàn mà lại thêm tươi, Trăng già mà lại hơn mười rằm xưa.” Đoạn nàng Kiều tái hợp chàng Kim này, năm 2015, từng được ngài Joe Biden, khi ấy là Phó Tổng thống Hoa Kỳ, đọc và dùng như một sứ điệp ngoại giao khi đãi quốc yến phái đoàn Việt Nam. Nếu cuộc đời truân chuyên của nàng Kiều đã trở thành ngôn ngữ của hòa giải và kết nối văn hóa theo cách lạ lùng như vậy, thì cũng kỳ lạ chẳng kém việc chuyện tình của Kim, của Vân, của Kiều, vốn dĩ xảy ra ở tận đầu tận đâu, vẫn không ngừng khuyến khích chiêm nghiệm và sáng tạo, rồi trở thành tiếng lòng dân tộc. Lần đầu tiên Kim Vân Kiều do học giả Nguyễn Văn Vĩnh dịch và chú giải cẩn thận ra quốc ngữ, kèm minh họa nhân vật theo bản in năm 1923, cùng bộ tranh Kiều chưa từng công bố của danh họa Nguyễn Tư Nghiêm, đã đồng thời xuất hiện trong ấn bản Kim Vân Kiều năm 2025 của Nhã Nam để kỷ niệm 260 năm ngày sinh và 205 năm ngày mất đại thi hào Nguyễn Du (1765–1820). Một kiệt tác văn chương, một di sản quốc ngữ, một thành tựu hội họa, tất cả, tạo nên một không gian thẩm mỹ, xứng đáng được chào đón và thưởng lãm.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935235247437.jpg', 195500.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(446, 'Em Lớn Lên Cùng Ca Dao, Tục Ngữ, Thành Ngữ - Trách Nhiệm', '8934974212638', '2026', 112, 85, 22, 24, 10, 'trong_nuoc', 'Bìa Mềm', 'Em Lớn Lên Cùng Ca Dao, Tục Ngữ, Thành Ngữ - Trách Nhiệm\nTrong kho tàng văn học dân gian, ông cha ta đã đúc rút từ quy luật của tự nhiên, xã hội thành những kinh nghiệm, kiến thức hết sức quý giá được thể hiện bằng những câu ca dao, tục ngữ, thành ngữ. Trải qua thời gian, những kinh nghiệm, kiến thức đó ngày càng được bồi đắp, gìn giữ và được ông cha ta truyền lại cho các thế hệ sau học tập và noi theo. Ca dao, tục ngữ, thành ngữ Việt Nam là những câu nói ngắn gọn, súc tích, có vần, có điệu, dễ nhớ về mọi cách ăn, nếp ở, mọi “phép tắc” ứng xử ở đời,… trong đó chứa đựng những bài học sâu sắc về con người và xã hội và đến ngày nay vẫn còn nguyên giá trị. Bộ sách Em lớn lên cùng ca dao, tục ngữ, thành ngữ gồm 9 tập: Rèn thân; Luyện chí; Sống đẹp; Nhân từ; Biết ơn; Tình thân; Hiếu thảo; Đoàn kết; Trách nhiệm gồm các câu ca dao, tục ngữ, thành ngữ về các chủ đề rèn thân, rèn trí, sống đẹp, nhân từ, biết ơn, tình thân, hiếu thảo, đoàn kết, trách nhiệm để rút ra bài học về cuộc sống, để rèn luyện, để trưởng thành cho các em thiếu nhi.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/n/x/nxbtre_full_29232025_032354.jpg', 55000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(447, 'Em Lớn Lên Cùng Ca Dao, Tục Ngữ, Thành Ngữ - Hiếu Thảo', '8934974212614', '2026', 108, 85, 22, 24, 10, 'trong_nuoc', 'Bìa Mềm', 'Em Lớn Lên Cùng Ca Dao, Tục Ngữ, Thành Ngữ - Hiếu Thảo\nTrong kho tàng văn học dân gian, ông cha ta đã đúc rút từ quy luật của tự nhiên, xã hội thành những kinh nghiệm, kiến thức hết sức quý giá được thể hiện bằng những câu ca dao, tục ngữ, thành ngữ. Trải qua thời gian, những kinh nghiệm, kiến thức đó ngày càng được bồi đắp, gìn giữ và được ông cha ta truyền lại cho các thế hệ sau học tập và noi theo. Ca dao, tục ngữ, thành ngữ Việt Nam là những câu nói ngắn gọn, súc tích, có vần, có điệu, dễ nhớ về mọi cách ăn, nếp ở, mọi “phép tắc” ứng xử ở đời,… trong đó chứa đựng những bài học sâu sắc về con người và xã hội và đến ngày nay vẫn còn nguyên giá trị. Bộ sách Em lớn lên cùng ca dao, tục ngữ, thành ngữ gồm 9 tập: Rèn thân; Luyện chí; Sống đẹp; Nhân từ; Biết ơn; Tình thân; Hiếu thảo; Đoàn kết; Trách nhiệm gồm các câu ca dao, tục ngữ, thành ngữ về các chủ đề rèn thân, rèn trí, sống đẹp, nhân từ, biết ơn, tình thân, hiếu thảo, đoàn kết, trách nhiệm để rút ra bài học về cuộc sống, để rèn luyện, để trưởng thành cho các em thiếu nhi.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/n/x/nxbtre_full_29222025_032203_1.jpg', 55000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(448, 'Em Lớn Lên Cùng Ca Dao, Tục Ngữ, Thành Ngữ - Đoàn Kết', '8934974212621', '2026', 112, 85, 22, 24, 10, 'trong_nuoc', 'Bìa Mềm', 'Em Lớn Lên Cùng Ca Dao, Tục Ngữ, Thành Ngữ - Đoàn Kết\nTrong kho tàng văn học dân gian, ông cha ta đã đúc rút từ quy luật của tự nhiên, xã hội thành những kinh nghiệm, kiến thức hết sức quý giá được thể hiện bằng những câu ca dao, tục ngữ, thành ngữ. Trải qua thời gian, những kinh nghiệm, kiến thức đó ngày càng được bồi đắp, gìn giữ và được ông cha ta truyền lại cho các thế hệ sau học tập và noi theo. Ca dao, tục ngữ, thành ngữ Việt Nam là những câu nói ngắn gọn, súc tích, có vần, có điệu, dễ nhớ về mọi cách ăn, nếp ở, mọi “phép tắc” ứng xử ở đời,… trong đó chứa đựng những bài học sâu sắc về con người và xã hội và đến ngày nay vẫn còn nguyên giá trị. Bộ sách Em lớn lên cùng ca dao, tục ngữ, thành ngữ gồm 9 tập: Rèn thân; Luyện chí; Sống đẹp; Nhân từ; Biết ơn; Tình thân; Hiếu thảo; Đoàn kết; Trách nhiệm gồm các câu ca dao, tục ngữ, thành ngữ về các chủ đề rèn thân, rèn trí, sống đẹp, nhân từ, biết ơn, tình thân, hiếu thảo, đoàn kết, trách nhiệm để rút ra bài học về cuộc sống, để rèn luyện, để trưởng thành cho các em thiếu nhi.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/n/x/nxbtre_full_29112025_031101.jpg', 55000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(449, 'Vết Thương Rồi Sẽ Nở Hoa', '8935325033476', '2026', 240, 86, 23, 14, 10, 'trong_nuoc', 'Bìa Mềm', 'Vết Thương Rồi Sẽ Nở Hoa\nCó những ngày trái tim ta như một khu vườn sau cơn bão, tan tác và đầy rẫy những vết xước. Vào những lúc như thế, ta không cần những lời khuyên lớn lao, mà chỉ cần một bàn tay dịu dàng chạm vào vết thương, thầm thì rằng: \"Mọi chuyện rồi sẽ ổn thôi\". Cuốn sách song ngữ \"Vết thương rồi sẽ nở hoa\" của Cô Giáo Quỳnh chính là bàn tay vỗ về ấy, một liều thuốc cho tâm hồn được dệt nên từ những sợi tơ ngôn ngữ mong manh nhưng đầy sức sống.\nCuốn sách được chia thành những chặng cảm xúc quen thuộc: từ rung động, đơn phương, yêu thương, chia ly cho đến chữa lành. Mỗi phần giống như một lát cắt rất thật của hành trình yêu và trưởng thành. Để rồi ở chương cuối cùng - “Chữa lành” - tác giả đã nhẹ nhàng gieo xuống những hạt mầm hy vọng, nhắc nhở ta rằng ngay cả những vết sẹo sần sùi nhất cũng có thể trở thành nơi những bông hoa rực rỡ nhất bắt đầu nảy mầm:\n“Ngày em chọn buông những điều dang dở,', NULL, 'https://cdn1.fahasa.com/media/catalog/product/_/n/_nh-b_a-1_4.jpg', 84000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
(450, 'Truyện Kiều Hội Bản - Ấn Bản Sơn Mài', '8935280921023', '2025', 324, 87, 9, 9, 10, 'trong_nuoc', 'Bộ Hộp', 'Truyện Kiều Hội Bản\nCảo thơm lần giở trước đèn\nPhong tình có lục còn truyền sử xanh.\nTruyện Kiều là một kiệt tác của Đại thi hào dân tộc Nguyễn Du, đồng thời đó cũng là một trong những kiệt tác của nền văn chương cổ điển Việt Nam. Truyện Kiều là truyện thơ Nôm viết theo thể lục bát, dựa theo tác phẩm Kim Vân Kiều truyện của Thanh Tâm Tài Nhân, Trung Quốc. Hàng trăm năm qua, Truyện Kiều đã sống chan hòa trong đời sống của toàn dân tộc. “Người trong nước từ kẻ ngu phu ngu phụ cho chí đến người có văn học, ai cũng biết, ai cũng đọc, mà ai cũng chịu là hay”.\nKể từ khi ra đời cho đến sau này, Truyện Kiều đã “gây nên một cơn sốt trong làng văn Việt Nam”. “Cơn sốt” đó đã tạo nên hai xu hướng chính trong việc truyền bá và thưởng thức tác phẩm. Xu hướng thứ nhất là việc Truyện Kiều đã được tổ chức khắc in, sao chép, tái bản nhiều lần, kéo theo đó là việc phiên âm, chú giải, bình luận về Truyện Kiều đã được tiến hành rầm rộ, đều đặn trên khắp cả nước. Xu hướng thứ hai, đó là vấn đề Truyện Kiều đã trở thành “một đề tài được chú ý của văn nhân tài tử Việt Nam”. Người ta không chỉ thưởng thức Truyện Kiều mà còn đua nhau đề Kiều, vịnh Kiều, hát Kiều, đố Kiều, bói Kiều, lẩy Kiều, tập Kiều; không những vậy, Truyện Kiều còn được dịch từ thơ Nôm của Nguyễn Du ra thơ chữ Hán theo các thể lục bát, song thất lục bát, thất ngôn bát cú”. Và hơn thế nữa, Truyện Kiều còn diễn dịch, chuyển hóa thành các thể loại văn học nghệ thuật khác nhau, như phú, diễn ca, tuồng, chèo...', NULL, 'https://cdn1.fahasa.com/media/catalog/product/a/n/an-ban-son-mai_truyen-kieu-hoi-ban_nguyen-du-_4_.jpg', 4000000.00, NULL, 20, '2026-03-10 11:24:36', '2026-03-10 11:24:36'),
