(688, 'Con Gái À! - Tự Bảo Vệ Mình Là Quan Trọng Nhất', '8935380700511', '2025', 112, 268, 8, NULL, 18, 'trong_nuoc', 'Bìa Mềm', 'Con Gái À! - Tự Bảo Vệ Mình Là Quan Trọng Nhất\nCuốn sách cung cấp các kiến thức về an toàn và phòng tránh nguy hiểm cho bé gái, từ những tình huống trong gia đình, trường học, ngoài xã hội, môi trường mạng, các tình huống bất ngờ trong cuộc sống. Thông qua những ví dụ cụ thể và minh họa trực quan, cuốn sách giúp các bé gái hiểu được cách bảo vệ chính mình và giảm thiểu nguy cơ bị tổn thương.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935380700511.jpg', 83000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(689, 'Những Câu Chuyện Tò Mò Của Bé - Con Có Thể Đánh Trả Khi Bị Bắt Nạt Không?', '8935212361910', '2022', 24, 269, 9, 1, 18, 'trong_nuoc', 'Bìa Mềm', 'Đây là Jack. Cậu bé khá là mạnh dạn và thích đưa ra nhiều câu hỏi khác thường.\nĐây là mẹ. Mẹ có khả năng trả lời mọi câu hỏi - cho dù chúng có kỳ quặc ra sao đi chăng nữa.\nTrong cuốn sách này, ba kẻ bắt nạt xấu xa đã lấy trộm quả bóng của Jack. Jack muốn dạy cho họ một bài học, nhưng mẹ lại có một ý tưởng khác…', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212361910.jpg', 22000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(690, 'Giáo Dục Đầu Đời Cho Trẻ - Những Bài Học Tự Bảo Vệ Bản Thân - Nguy Hiểm Đấy, Mau Tránh Xa', '8935212362436', '2022', 48, 265, 13, 1, 18, 'trong_nuoc', 'Bìa Mềm', 'Giáo Dục Đầu Đời Cho Trẻ - Những Bài Học Tự Bảo Vệ Bản Thân - Nguy Hiểm Đấy, Mau Tránh Xa\nTrong xã hội ngày nay, việc trang bị cho trẻ em những kiến thức an toàn để tự bảo vệ bản thân là điều hết sức cần thiết. Thấu hiểu điều này, bộ sách Giáo dục đầu đời cho trẻ - Những bài học tự bảo vệ bản thân đã ra đời nhằm giúp các em nhận thức rõ về cơ thể mình, bồi dưỡng những quan niệm đúng đắn về giới tính, đồng thời nắm được những nguy cơ tiềm tàng trong cuộc sống, tránh xa mọi hiểm nguy.\nVới nội dung được lồng ghép tinh tế kèm tranh minh họa sinh động, chắc chắn các em sẽ tiếp thu những điều bổ ích trong sách rất nhanh và dễ dàng áp dụng vào cuộc sống đấy! Hãy mở sách và khám phá nhé!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212362436.jpg', 33500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(691, 'Cẩm Nang Con Gái', '8935380700603', '2025', 196, 270, 6, NULL, 18, 'trong_nuoc', 'Bìa Mềm', 'Cẩm Nang Con Gái\nCuốn sách giải đáp những băn khoăn của tuổi dậy thì cho các bé gái, đồng thời cung cấp cho phụ huynh phương pháp thấu hiểu, đồng hành cùng con qua giai đoạn này', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935380700603.jpg', 102000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(692, 'Gieo Mầm Yêu Thương - Bồn Tắm Của Lửng', '8935212374477', '2025', 24, 271, 7, 1, 18, 'trong_nuoc', 'Bìa Mềm', 'Gieo Mầm Yêu Thương - Bồn Tắm Của Lửng\nLửng đang làm việc mà những bạn lửng làm giỏi nhất: Đào xới. Cậu đã có một ngày dễ thương, và như thường lệ, khi cậu có một ngày dễ thương, nghĩa là cậu đã bẩn ơi là bẩn rồi đấy.\n“Bác rất tiếc.” Bác bảo vệ công viên Percy nói.\n“Nhưng mà cháu không thể tới uống trà với bộ dạng này được.” Lửng trông có vẻ thất vọng.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212374477.jpg', 33000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(693, 'Mỗi Ngày Một Câu Chuyện - One Story A Day - 365 Câu Chuyện Truyền Cảm Hứng Được Viết Bởi Các Chuyên Gia Giáo Dục Hàng Đầu Canada - Tháng 1', '8938537634837', '2023', 68, 272, 1, 46, 18, 'trong_nuoc', 'Bìa Mềm', 'One Story a Day (Beginners collection) - Mỗi ngày một câu chuyện là bộ sách gồm 12 cuốn tương ứng với 12 tháng trong một năm được xây dựng nhằm mục đích phát triển tình yêu đọc sách và niềm hứng khởi với tiếng Anh dành cho các bạn nhỏ trong lứa tuổi 5-12.\nĐây được coi là “bộ sách mang lại lợi ích suốt đời cho người đọc”, một bộ sách lưu truyền qua thế hệ bởi nó được biên soạn bởi các chuyên gia giáo dục hàng đầu Canada. One Story a Day là 365 câu chuyện tương ứng với 365 ngày trong một năm về các chủ đề gần gũi trong cuộc sống hằng ngày, được kể lại một cách cực kỳ khoa học và sinh động. Lồng vào đó là lượng kiến thức khổng lồ dành cho các bạn nhỏ về tự nhiên, khoa học, lịch sử, trái đất, vũ trụ …', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8938537634837.jpg', 31500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(694, 'Bé Học Điều Tốt - Bé Làm Điều Hay - Đúng Giờ Như Bạn Gà Tơ', '8934974205487', '2024', 24, 273, 22, 24, 18, 'trong_nuoc', 'Bìa Mềm', 'Bé Học Điều Tốt - Bé Làm Điều Hay - Đúng Giờ Như Bạn Gà Tơ\nGà Tơ có thói quen làm gì cũng đúng giờ: đi ngủ đúng giờ, thức dậy đúng giờ, ăn uống đúng giờ, đi học đúng giờ...\nBé nhớ đọc hết quyển sách để tìm hiểu xem, Gà Tơ còn đúng giờ trong những việc gì nữa, và có phải nhờ vào thói quen tốt này mà bạn ấy luôn đúng hẹn, được tin tưởng và luôn có tinh thần sảng khoái, vui vẻ cũng như năng lượng tích cực cho cả ngày không nhé.\nĐúng giờ như bạn Gà Tơ - là 1 trong 10 tựa của bộ sách “Bé học điều tốt – Bé làm điều hay”. 10 tựa sách là những “cẩm nang” kỹ năng sống nho nhỏ, song hành cùng bé trong hành trình bé đang lớn lên cả về thể chất lẫn trí tuệ. Giúp bé tự giác xây dựng những thói quen tốt và nền nếp ngay từ nhỏ như: đúng giờ, tự lập, sạch sẽ.. cùng những đức tính hướng thiện như: trung thực, ấm áp, kiên trì, tự tin, vị tha… Học điều tốt, bé sẽ làm được những điều hay như biết quan tâm người khác, biết giữ lời hứa, biết điều chỉnh cảm xúc và hành vi, biết chia sẻ và giúp đỡ, biết tôn trọng mọi người.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8934974205487.jpg', 22500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(695, 'Cẩm Nang An Toàn Tự Bảo Vệ Dành Cho Bé Gái - Con Gái À! Tự Bảo Vệ Bản Thân Mình Là Tốt Nhất', '8935236438100', '2025', 118, 274, 2, 45, 18, 'trong_nuoc', 'Bìa Mềm', 'Cẩm Nang An Toàn Tự Bảo Vệ Dành Cho Bé Gái - Con Gái À! Tự Bảo Vệ Bản Thân Mình Là Tốt Nhất\nTrong thời đại hiện nay, khi xã hội ngày càng phát triển, trẻ em phải đối diện với vô vàn nguy cơ tiềm ẩn: từ những tai nạn nhỏ trong sinh hoạt hằng ngày đến các tình huống phức tạp ngoài xã hội. Nhiều phụ huynh luôn băn khoăn: “Liệu con mình đã thực sự biết cách tự bảo vệ bản thân chưa?”\nĐây cũng chính là lý do mà bộ sách “Tự bảo vệ bản thân mình là tốt nhất” ra đời. Với cách tiếp cận nhẹ nhàng, gần gũi, kết hợp minh họa sinh động, cuốn sách trở thành người bạn đồng hành đáng tin cậy của trẻ, đồng thời là cầu nối gắn kết giữa cha mẹ và con cái trong việc xây dựng kỹ năng sống an toàn.\nKhông đơn thuần là một cuốn sách kỹ năng, “Tự bảo vệ bản thân mình là tốt nhất” còn là “chiếc áo giáp tinh thần” giúp trẻ biết nhận diện nguy hiểm, tự tin ứng phó và trưởng thành hơn trong tư duy bảo vệ bản thân.\nƯU ĐIỂM NỔI BẬT', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935236438100_1.jpg', 54000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(696, 'Bồi Dưỡng Tính Cách Cho Bé EQ IQ (2-8 Tuổi) - Dạy Trẻ Không Sợ Hãi (Song Ngữ Anh - Việt)', '8935236429016', '2022', 24, 267, 10, 45, 18, 'trong_nuoc', 'Bìa Mềm', 'Giống như những mầm cây, trẻ em cần được bởi dưỡng và rèn luyện tính cách ngay khi còn nhỏ, để các bé có thêm kiến thức và dũng khí đối diện với khó khăn, giải quyết những thách thức trong cuộc sống. Hãy để bộ sách Bồi dưỡng tính cách cho bé EQ-10 làm người bạn tâm hồn của các bé, giúp các bé thu thập lòng tự tin và sức mạnh để trưởng thành!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935236429016.jpg', 28000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(697, 'Kỹ Năng Quản Lý Cảm Xúc Dành Cho Bé Gái - Tớ Không Chỉ Là Cô Bé Ngoan', '8935212365567', '2023', 32, 275, 9, 1, 18, 'trong_nuoc', 'Bìa Mềm', 'Kỹ Năng Quản Lý Cảm Xúc Dành Cho Bé Gái - Tớ Không Chỉ Là Cô Bé Ngoan\nMình tên là Tuệ, và mình cảm thấy bản thân có chút đặc biệt, bởi vì trong cơ thể mình có hai cô gái. Suỵt, đây là một bí mật đấy nhé! Trong hai cô gái này, một bạn là cô gái ngoan ngoãn, còn một bạn là cô gái nghịch ngợm.\n“Cô gái ngoan ngoãn này, nhìn xem, bạn chẳng nghiêm túc chút nào!”\n“Cô gái nghịch ngợm này, bạn nhìn bản thân xem, chẳng ra làm sao cả!”\nHai cô gái cứ “đấu khẩu” suốt trong đầu mình như vậy đấy.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212365567.jpg', 31000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(698, 'Gieo Mầm Yêu Thương - Bài Học Của Cú', '8935212374453', '2025', 24, 271, 7, 1, 18, 'trong_nuoc', 'Bìa Mềm', 'Gieo Mầm Yêu Thương - Bài Học Của Cú\nNhững chú chim én và chim nhạn lượn bay cao phía trên đầu của bác bảo vệ công viên Percy. Chẳng mấy chốc, chúng sẽ rời đi tận hưởng chuyến nghỉ đông dài của mình. Vài loài chim đã bay đi rồi đấy.\nBác Percy đang nghĩ sẽ tuyệt biết mấy nếu bác được bay cùng chúng, nhưng những suy nghĩ của bác đã sớm bị đưa trở xuống mặt đất.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212374453.jpg', 33000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(699, 'Bộ Gieo Hạt Cùng Vĩ Nhân - Bộ 2 - Tập 13', '9786044501161', '2025', 56, 276, 46, NULL, 18, 'trong_nuoc', 'Bìa Mềm', 'Gieo Hạt Cùng Vĩ Nhân - Bộ 2 - Tập 13\nGieo Hạt Cùng Vĩ Nhân Là những tập truyện nằm trong dự án của Cộng Đồng Sống Tử Tế với trăn trở:\nThấy từng đứa trẻ được đọc Nhân Quả Đạo Đức từ nhỏ, được bố mẹ cùng hỏi con về các câu Nhân Quả, về từng tấm gương Vĩ Nhân. Được thấy trẻ tự biết điều gì đúng đắn và hướng thiện nên làm.\nPhần 1: Tích truyện vĩ nhân:\n– Nội dung phong phú và lôi cuốn kể về các đóng góp to lớn của các Vĩ Nhân trong và ngoài nước\n– ĐẶC BIỆT được phân tích sâu sắc Nguyên nhân – Kết quả để con biết rõ điều gì dẫn đến thành công của Vĩ Nhân đó nuôi dưỡng hoài bão ước mơ, con hình thành nhân cách đúng đắn từ đó xác định lý tưởng sống cao đẹp biết giúp người giúp đời.\nTrẻ sẽ sớm biết xu hướng mình đam mê lĩnh vực gì nhất thông qua 100 Vĩ Nhân trong hơn 10 lĩnh vực của cuộc sống.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/7/9786044501161.jpg', 27000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(700, 'Bộ Gieo Hạt Cùng Vĩ Nhân - Bộ 2 - Tập 16', '9786044501192', '2025', 56, 276, 46, NULL, 18, 'trong_nuoc', 'Bìa Mềm', 'Gieo Hạt Cùng Vĩ Nhân - Bộ 2 - Tập 16\nGieo Hạt Cùng Vĩ Nhân Là những tập truyện nằm trong dự án của Cộng Đồng Sống Tử Tế với trăn trở:\nThấy từng đứa trẻ được đọc Nhân Quả Đạo Đức từ nhỏ, được bố mẹ cùng hỏi con về các câu Nhân Quả, về từng tấm gương Vĩ Nhân. Được thấy trẻ tự biết điều gì đúng đắn và hướng thiện nên làm.\nPhần 1: Tích truyện vĩ nhân:\n– Nội dung phong phú và lôi cuốn kể về các đóng góp to lớn của các Vĩ Nhân trong và ngoài nước\n– ĐẶC BIỆT được phân tích sâu sắc Nguyên nhân – Kết quả để con biết rõ điều gì dẫn đến thành công của Vĩ Nhân đó nuôi dưỡng hoài bão ước mơ, con hình thành nhân cách đúng đắn từ đó xác định lý tưởng sống cao đẹp biết giúp người giúp đời.\nTrẻ sẽ sớm biết xu hướng mình đam mê lĩnh vực gì nhất thông qua 100 Vĩ Nhân trong hơn 10 lĩnh vực của cuộc sống.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/7/9786044501192.jpg', 27000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(701, 'Bộ Bé Yêu Tô Màu - Đội Chó Cứu Hộ Paw Patrol - Tập 4', '8935072954154', '2020', 16, 277, 47, NULL, 32, 'trong_nuoc', 'Bìa Mềm', 'Bé Yêu Tô Màu - Đội Chó Cứu Hộ Paw Patrol - Tập 4\nTập tô màu là hoạt động ưa thích của các bé. Hoạt động này không những giúp rèn luyện đôi tay khéo léo, đức tính kiên trì mà còn có thể bồi dưỡng cho bé khả năng nhận biết màu sắc, phát triển óc sáng tạo. Mỗi khi hoàn thành một bức tranh tô màu, bé sẽ dễ dàng khắc sâu hình ảnh thế giới xung quanh hình thành nên quan niệm thẩm mỹ về thế giới quan.\nBộ sách được thực hiện với mong muốn vừa thỏa mãn sở thích, vừa mang lại cho bé cơ hội bồi dưỡng kiến thức đầy hữu ích.\nMỗi trang tô màu gồm có 2 phần:\nPhần hình mẫu (in màu)\nPhần hình tô với kích thước lớn, đường nét rõ ràng.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935072954154.jpg', 9500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(702, 'Bộ Tập Tô Mẫu Giáo - Nét Cơ Bản 1 (Dành Cho 3-4 Tuổi)', '8936036315394', '2021', 23, 22, 48, NULL, 32, 'trong_nuoc', 'Bìa Mềm', 'Tập Tô Mẫu Giáo - Nét Cơ Bản 1 (Dành Cho 3-4 Tuổi)\nNhững kiến thức cơ bản về ghép vần và tập viết là hành trang đầu tiên cho bé yêu nhà bạn bước vào lớp 1 vững chắc nhất.\nBởi vậy, ngay từ lúc này bạn hãy chuẩn bị giáo án cho bé tập ghép vần và tập viết ngay nào.\nBộ sách sẽ là tài liệu không thể thiếu với các bé mầm non chuẩn bị vào lớp 1.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8936036315394.jpg', 10000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(703, 'Draw Kawaii In 5 Simple Steps - Vẽ Theo Phong Cách Kawaii Với 5 Bước Đơn Giản', '8935212352888', '2020', 80, 278, 12, 1, 32, 'trong_nuoc', 'Bìa Mềm', 'Draw Kawaii in 5 simple steps  -  Vẽ theo phong cách Kawaii với 5 bước đơn giản\nEm đã sẵn sàng trổ tài hội họa chỉ với 5 bước vẽ chưa? Từ chú tắc kè hoa sặc sỡ cho đến chú chim công đỏm dáng, từ chiếc thuyền đang dong buồm ra khơi cho đến ngọn hải đăng đang chiếu sáng rực rỡ..., tất cả đều có trong Draw Kawaii in 5 simple steps  -  Vẽ theo phong cách Kawaii với 5 bước đơn giản. Ngoài hướng dẫn chi tiết, trong cuốn sách còn có một khoảng trống thật lớn để em thực hành ngay lập tức nữa đấy.\nHãy sẵn sàng để chìm đắm trong hội họa nào!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_197203.jpg', 55000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(704, 'Bé Yêu Tô Màu Đội Chó Cứu Hộ Paw Patrol', NULL, NULL, NULL, NULL, NULL, NULL, 32, 'trong_nuoc', NULL, NULL, NULL, NULL, 9500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(705, 'Bộ Sách Thú Vị Dành Cho Bé Nhập Môn Tập Tô - Bé Tập Tô Màu - Màu Hồng', '8935210285942', '2021', 47, 279, 20, 23, 32, 'trong_nuoc', 'Bìa Mềm', 'Bộ Sách Thú Vị Dành Cho Bé Nhập Môn Tập Tô - Bé Tập Tô Màu - Màu Hồng\nBộ sách thú vị dành cho bé nhập môn tập tô: Bé Tập Tô Màu - Màu Hồng (2-6 tuổi)\nCác bé ở lứa tuổi mầm non và mẫu giáo luôn muốn khám phá và tìm hiểu thế giới xung quanh. Tập tô là cách hữu ích giúp bé hoàn thiện được sự phát triển về thẩm mĩ. Với các bức hình sinh động, màu sắc tươi tắn, cuốn sách sẽ giúp bé có những giờ phút vui vẻ khi tô màu, phát triển thị giác, tư duy và rèn luyện sự khéo léo của đôi bàn tay.\nTrong cuốn sách, người biên soạn đã nhìn từ góc độ của trẻ em ở lứa tuổi này để chọn ra những bức tranh có màu sắc tươi sáng, hình ảnh sinh động có chủ đề là cuộc sống hàng ngày để cho bé tập tô. Mỗi một bức tranh đều có các bước tô màu để hướng dẫn cho bé từng bước tiến hành luyện tập, đồng thời có lời hướng dẫn cách phối hợp màu sắc, bồi dưỡng những kỹ năng tô màu và khả năng tư duy lôgic của bé. Dần dần các bé sẽ nắm bắt được những quy tắc cơ bản về hội họa và màu sắc.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935210285942.jpg', 28000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(706, 'Bé Tập Làm Họa Sĩ - Tập Vẽ Động Vật', '8936067610567', '2024', 40, 280, 49, 5, 32, 'trong_nuoc', 'Bìa Mềm', 'SERIES BÉ TẬP LÀM HỌA SĨ\nQuan tâm đến việc chỉ dẫn và bồi dưỡng những nét vẽ đầu tiên của trẻ nhỏ là điều hết sức cần thiết, bởi nó giúp thúc đẩy khả năng quan sát, ghi nhớ của trẻ, tạo cơ sở nền tảng vững chắc cho sự phát triển toàn diện sau này.\nBộ 6 cuốn sách Bé Tập Làm Họa Sĩ với 6 chủ đề khác nhau:\n1. Bé Làm Họa Sĩ Tập Vẽ Từ Hình Đa Giác\n2. Bé Làm Họa Sĩ Tập Vẽ Từ Đường Cong\n3. Bé Làm Họa Sĩ Tập Vẽ Từ Hình Chữ Nhật\n4. Bé Làm Họa Sĩ Tập Vẽ Phương Tiện Giao Thông\n5. Bé Làm Họa Sĩ Tập Vẽ Động Vật', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8936067610567.jpg', 32000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(707, 'Bộ Hay Vẽ Thì Vẽ Hay - Tập 4 - Nhân Vật Manga Thu Hút', '8936071299840', '2024', 30, 281, 1, 48, 32, 'trong_nuoc', 'Bìa Mềm', 'Hay Vẽ Thì Vẽ Hay - Tập 4 - Nhân Vật Manga Thu Hút\nChỉ bằng vài bước đơn giản, bé có thể vẽ những gì bé thích. Cuốn sách Hay Vẽ Thì Vẽ Hay sẽ giúp bé tạo ra những hình ảnh ngộ nghĩnh, đáng yêu với các chủ đề gần gũi, phong phú về động vật, thiên nhiên, đồ dùng, con người,… Sách tập vẽ này có hướng dẫn từng bước cho các họa sĩ nhí bắt tay vào vẽ bức tranh đầu đời.\nThiết kế tạo hình một nhân vật hoạt hình manga khá khác biệt với việc vẽ tranh, phác thảo nhân vật một lần. Khi vẽ một lần, bạn chỉ quan tâm nhân vật trông như thế nào từ một góc nhìn trong bức tranh đó. Nhưng khi vẽ truyện tranh; hoạt hình; việc thiết kế nhân vật, cần bạn phải vẽ từ nhiều góc nhìn/góc độ khác nhau để tạo nên tính đa dạng. Đáp ứng mọi tình huống xảy ra trong câu chuyện của mình.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/4/_/4_cover1_1.jpg', 21000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(708, 'Luyện Tay Cầm Bút - Tập Tô Chữ (Dành Cho 4-5 Tuổi)', '8931805616757', '2022', 23, 282, 50, 36, 32, 'trong_nuoc', 'Bìa Mềm', 'Luyện Tay Cầm Bút - Tập Tô là một bộ sách có tính hướng dẫn cao cho các bé tập đồ theo nét các chữ cái Tiếng Việt. Luyện Tay Cầm Bút - Tập Tô sẽ giúp con bạn học viết và giải quyết các vấn đề trong nội dung phân môn Tập Viết trong trường Tiểu học.\nBộ sách giúp dạy, cải thiện và củng cố việc học viết.\nPhát triển và nâng cao kỹ năng tự học tại nhà với các bài tập viết đơn giản.\nGiúp trẻ em bắt đầu học viết các chữ cái trong bảng chữ cái và cải thiện khả năng viết tay của các bé. Dạy bé cách kiểm soát bút thích hợp, dò dòng và hơn thế nữa.\nGiúp bé tự tin hơn khi ở trường, nâng cao khả năng đọc và viết cho các bé.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8931805616757.jpg', 11500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(709, 'Cuốn Sách Tô Màu Đầu Tiên Của Tớ - Khủng Long', '8935212358149', '2022', 32, 283, 13, 1, 32, 'trong_nuoc', 'Bìa Mềm', 'Tô màu giúp các bé làm quen với thế giới màu sắc đa dạng, rèn luyện những thao tác cơ bản: cầm bút, phân biệt hình khối, cảm nhận sự hài hòa... Đây là hoạt động vừa học vừa chơi thú vị, kích thích trí tưởng tượng, khám phá và sáng tạo của trẻ.\nBộ sáchCuốn Sách Tô Màu Đầu Tiên Của Tớgồm các chủ đề :\n• Cuốn sách tô màu đầu tiên của tớ - Động vật\n• Cuốn sách tô màu đầu tiên của tớ - Côn trùng\n• Cuốn sách tô màu đầu tiên của tớ - Giáng sinh\n• Cuốn sách tô màu đầu tiên của tớ - Khủng long\n• Cuốn sách tô màu đầu tiên của tớ - Khu vườn xinh đẹp\n• Cuốn sách tô màu đầu tiên của tớ - Halloween', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212358149.jpg', 20000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(710, 'Bộ Luyện Nét Chữ Rèn Nết Người - Vở Ô Li Có Mẫu Chữ - Lớp 1 - Quyển 1 (Tái Bản 2020)', '8935095629077', '2020', 48, 284, 20, 4, 32, 'trong_nuoc', 'Bìa Mềm', 'Bộ sách Luyện nét chữ rèn nết người hướng dẫn các em viết chữ đẹp.\nCha mẹ và các em hãy đón mua!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_32301.jpg', 16000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(711, 'Bé Tập Tô Màu - Động Vật (2022)', '8936067607161', '2022', 24, 285, 49, 5, 32, 'trong_nuoc', 'Bìa Mềm', 'Lứa tuổi mẫu giáo là lứa tuổi cực kì quan trọng trong sự phát triển của bé, đây là lứa tuổi mà bé bắt đầu tìm hiểu về thế giới vạn vật xung quanh, là độ tuổi phát triển nhanh về mặt tư duy cũng như nhận thức của trẻ. Chính vì vậy việc giúp bé học và tham gia các trò chơi phù hợp đóng vai trò rất quan trọng.\nTô màu giúp bé phát triển tư duy, trí tuệ. Đây cũng là hình thức khơi gợi trí tưởng tượng, kích thích tinh thần ham học hỏi, khám phá thế giới xung quanh của các em. Những sắc màu tươi sáng, sinh động,những sự vật quen thuộc trong đời sống sẽ hình thành nên niềm đam mê hội hoạ tuổi thơ.\nBé Tập Tô Màu là bộ sách vừa học vừa chơi dành cho thiếu nhi. Với chủ đề Động Vật, các bé sẽ tiếp tục vừa tô vừa nhận biết thêm các con vật như: con mèo, gà con, ốc sên, con thỏ, con cừu, con voi, con hổ, con vịt, bạch tuộc,…', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8936067607161.jpg', 9600.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(712, 'Bộ Sách Yêu Quá Việt Nam (Bộ 6 Cuốn) - Tặng Kèm Túi Đựng + Sticker + Bản Đồ Việt Nam', '8935212374408', '2025', 120, 286, 6, 1, 32, 'trong_nuoc', 'Bìa Mềm', 'Bộ Sách Yêu Quá Việt Nam (Bộ 6 Cuốn)\nBộ sách tô màu “Yêu Quá Việt Nam” là món quà đặc biệt cho các bạn nhỏ khám phá những nét đẹp văn hóa truyền thống trải khắp mọi miền Tổ Quốc với 6 chủ đề cực kỳ thú vị:\n- Lễ hội\n- Trò chơi dân gian\n- Trang phục truyền thống\n- Di sản\n- Các loài hoa\n- Món ngon ba miền', NULL, 'https://cdn1.fahasa.com/media/catalog/product/a/n/anh-san-pham-25-02.jpg', 120000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(713, 'Tủ Sách Vui Để Học - Dòng Sách Cầm Tay - Sách Tô Màu - Tô Màu Vào Khoảng Trống', '9786044729718', '2024', 64, 287, 10, 49, 32, 'trong_nuoc', 'Bìa Mềm', 'Tủ Sách Vui Để Học - Dòng Sách Cầm Tay - Sách Tô Màu - Tô Màu Vào Khoảng Trống\nTô màu vào khoảng trống: Quyển sách có kích thước nhỏ, phù hợp để làm người bạn đồng hành với bé đến bất cứ đâu. Khi bé vẽ vào các lỗ trống trên trang, bé sẽ tạo ra một bức tranh bất ngờ ở trang tiếp theo! Bé hãy thử tô thật nhiều, thật nhiều màu và chờ xem bức tranh sẽ biến hóa thế nào nhé!\nTrọn bộ tuyển tập sách tô màu và cắt dán vui nhộn đến từ tác giả minh họa người Nhật nổi tiếng – LaZOO.\nTuyển tập này đã đạt giải thưởng lớn trong Triển lãm sách dành cho trẻ em ở Bologna.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/7/9786044729718.jpg', 57500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(714, '200 Miếng Bóc Dán Thông Minh - Các Loài Động Vật (Tái Bản 2018)', '8935212339131', '2018', 36, 22, 21, 1, 32, 'trong_nuoc', 'Bìa Mềm', 'Đây là cuốn sách được tuyển chọn và những trò chơi dán hình, giúp cho đôi tay của các em thêm linh hoạt, khéo léo, nhận biết được các hình để bóc và dán cho đúng chỗ...\nTrong sách có tặng kèm hơn 80 miếng bóc dán. Xin trân trọng giới thiệu.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_175266.jpg', 44000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(715, 'Tập Tô Chữ - Mẫu Giáo 3-4 Tuổi', '8936036314618', '2021', 23, 288, 48, NULL, 32, 'trong_nuoc', 'Bìa Mềm', 'Tập Tô Chữ - Mẫu Giáo 3-4 Tuổi\nTrước khi vào lớp 1, các bé mẫu giáo cần được trang bị kiến thức cơ bản về chữ viết giúp các em có được sự tự tin khi tiếp xúc với môi trường học tập ở trường tiểu học.\nBộ sách Tập Tô Chữ giới thiệu tới các bé những nét chữ cơ bản và bảng chữ cái Tiếng Việt. Ngoài chữ viết, trong sách còn có những hình ảnh minh hoạ xinh xắn với màu sắc tươi sáng thu hút sự chú ý và sức tập trung của các bé.\nTập Tô Chữ Mẫu Giáo 3-4 Tuổi gồm các nội dung dung chính như sau:\nHướng dẫn kỹ thuật viết.\nCách cầm bút.\nĐường li vào dòng li.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8936036314618.jpg', 8500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54');
