(716, 'Bóc Dán Sử Dụng Nhiều Lần - Động Vật Nuôi', '8935212374330', '2025', 4, 289, 9, 1, 32, 'trong_nuoc', 'Bìa Mềm', 'Bóc Dán Sử Dụng Nhiều Lần - Động Vật Nuôi\nBÓC DÁN SỬ DỤNG NHIỀU LẦN (thỏa sức sáng tạo trên nhiều bề mặt)\nMang tới trò chơi cho con thỏa sức bóc dán nhiều lần mà không lo rách hỏng, dán được ở nhiều bề mặt khác nhau…\nChất liệu bền dai mềm, dễ bóc dán, ngâm nước không hỏng\nCon tự tay tạo nên bức tranh của riêng mình qua những miếng dán sáng tạo', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212374330_1.jpg', 67000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(717, 'Bộ Vở Ô Li Có Mẫu Chữ 1 - Quyển 1 (Sáng Tạo) (Tái Bản 2025)', '9786044337289', '2025', 48, 290, 51, NULL, 32, 'trong_nuoc', 'Bìa Mềm', 'Vở Ô Li Có Mẫu Chữ 1 - Quyển 1 (Sáng Tạo)\nTập hợp mẫu chữ giúp các bé rèn luyện chữ viết, tư thế ngồi và cách cầm bút đúng cách.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/u/n/untitled-1_5_12.jpg', 19500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(718, 'Bộ Sách Bé Tập Tô Phát Triển Tư Duy - Tập Tô-Tập Viết (Bộ 8 Cuốn)', '1374309911800', '2021', NULL, 291, 8, NULL, 32, 'trong_nuoc', 'Bìa Mềm', 'Bộ Sách Bé Tập Tô Phát Triển Tư Duy - Tập Tô-Tập Viết (Bộ 8 Cuốn)\nMột vấn đề luôn khiến ba mẹ cảm thấy đau đầu đó chính là việc chuẩn bị trước khi con chính thức bước vào tuổi đến trường. Nào là học bảng chữ cái, nào là học đếm số, rồi thì nỗi lo con không theo kịp bạn bè. Ở độ tuổi mầm non, trẻ còn hiếu động, dễ mất tập trung, chỉ hứng thú với trò chơi nên lại càng khó hơn cho ba mẹ. Có quá nhiều kiến thức và những thông tin trên mạng khiến bạn lúng túng và không biết bắt đầu từ đâu. Tuy nhiên, mọi việc sẽ trở nên dễ dàng hơn rất nhiều nếu như xuất hiện một “trợ thủ đắc lực” giúp đỡ trong quá trình này.\nBộ sách “Bé tập tô phát triển tư duy” đang chờ bạn khám phá qua 16 quyển sách xinh xắn, được chia thành 2 chủ đề chính là “Tập tô - tập viết” và “Câu đố tư duy”. Mỗi tập đều chứa những bài tập trực quan kết hợp cùng những trò chơi tư duy vui nhộn đem đến cho bé những trải nghiệm và kiến thức bổ ích.\nBộ sách bao gồm:', NULL, 'https://cdn1.fahasa.com/media/catalog/product/1/3/1374309911800.jpg', 104000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(719, 'Bộ Giúp Bé Vững Bước Vào Lớp 1 - Bé Làm Quen Với Chữ Cái - Quyển 1 (5-6 Tuổi) (Tái Bản 2024)', '8935210308559', '2024', 32, 71, 49, 23, 32, 'trong_nuoc', 'Bìa Mềm', 'Giúp Bé Vững Bước Vào Lớp 1 - Bé Làm Quen Với Chữ Cái - Quyển 1 (5-6 Tuổi)\nLà một trong những cuốn sách hổ trợ các bé khi bước vào lớp 1.\nQuyển sách này tiếp tục quyển 1 giúp các bé học tốt về các chữ cái ở lứa tuổi từ 5 tới 6 tuổi.\nVới cách hướng dẫn dễ hiểu , trình bày rõ ràng sẽ giúp dễ dàng tiếp thu và học thật tốt khi bước vào lớp 1. Sách đã được tiếp thu cải tiến về mặt giáo dục và biên soạn theo chương trình giáo dục mầm non mới.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_193572_1.jpg', 9500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(720, 'Bộ Hay Vẽ Thì Vẽ Hay - Tập 5 - Biểu Cảm Nhân Vật Sinh Động', '8936071299857', '2024', 24, 281, 1, 48, 32, 'trong_nuoc', 'Bìa Mềm', 'Hay Vẽ Thì Vẽ Hay - Tập 5 - Biểu Cảm Nhân Vật Sinh Động\nCuốn sách “Hay Vẽ Thì Vẽ Hay” là một nguồn tài nguyên tuyệt vời để khơi gợi niềm đam mê và sự sáng tạo trong nghệ thuật cho các bé từ 6 đến 12 tuổi.\nChỉ bằng vài bước đơn giản, bé có thể vẽ những gì bé thích. Cuốn sách Hay Vẽ Thì Vẽ Hay sẽ giúp bé tạo ra những hình ảnh ngộ nghĩnh, đáng yêu với các chủ đề gần gũi, phong phú về động vật, thiên nhiên, đồ dùng, con người,… Sách tập vẽ này có hướng dẫn từng bước cho các họa sĩ nhí bắt tay vào vẽ bức tranh đầu đời.\nHãy cùng nhau bắt đầu hành trình nghệ thuật với bé bằng cuốn sách Hay Vẽ Thì Vẽ Hay. Cuốn sách này giúp bé tiếp cận mọi thứ xung quanh thú vị, hiệu quả về việc nhìn và vẽ. Chúng tôi tin rằng, việc khơi dậy niềm đam mê nghệ thuật qua các hình khối từ nhỏ; sẽ giúp bé phát triển sự bộ não, xử lý thông tin thị giác một cách tốt nhất.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/z/6/z6161382066984_312dabda556e8fee4f455e6bd9c57a28.jpg', 21000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(721, 'Bộ Hay Vẽ Thì Vẽ Hay - Tập 6 - Trang Phục Và Phụ Kiện Bắt Mắt', '8936071299864', '2024', 24, 281, 1, 48, 32, 'trong_nuoc', 'Bìa Mềm', 'Hay Vẽ Thì Vẽ Hay - Tập 6 - Trang Phục Và Phụ Kiện Bắt Mắt\nCuốn sách “Hay Vẽ Thì Vẽ Hay” là một nguồn tài nguyên tuyệt vời để khơi gợi niềm đam mê và sự sáng tạo trong nghệ thuật cho các bé từ 6 đến 12 tuổi.\nChỉ bằng vài bước đơn giản, bé có thể vẽ những gì bé thích. Cuốn sách Hay Vẽ Thì Vẽ Hay sẽ giúp bé tạo ra những hình ảnh ngộ nghĩnh, đáng yêu với các chủ đề gần gũi, phong phú về động vật, thiên nhiên, đồ dùng, con người,… Sách tập vẽ này có hướng dẫn từng bước cho các họa sĩ nhí bắt tay vào vẽ bức tranh đầu đời.\nHãy cùng nhau bắt đầu hành trình nghệ thuật với bé bằng cuốn sách Hay Vẽ Thì Vẽ Hay. Cuốn sách này giúp bé tiếp cận mọi thứ xung quanh thú vị, hiệu quả về việc nhìn và vẽ. Chúng tôi tin rằng, việc khơi dậy niềm đam mê nghệ thuật qua các hình khối từ nhỏ; sẽ giúp bé phát triển sự bộ não, xử lý thông tin thị giác một cách tốt nhất.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/z/6/z6161382368926_edbde223188b8642c2e2271beabea786_1.jpg', 21000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(722, 'Tô Màu Baby Three Dễ Thương', '8935230010357', '2025', 26, 292, 1, 27, 32, 'trong_nuoc', 'Bìa Mềm', 'Tô Màu Baby Three Dễ Thương\nTô màu Baby Three là cuốn sách tô màu dễ thương, với những nhân vật Baby Three ngộ nghĩnh, gần gũi và tràn đầy năng lượng.\nNét vẽ đơn giản, dễ tô giúp bé thư giãn, rèn luyện khả năng tập trung, phối màu và phát triển trí tưởng tượng một cách tự nhiên.\nMột cuốn sách tô màu nhẹ nhàng, để mỗi trang sách là một khoảnh khắc vui vẻ của bé', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935230010357.jpg', 27000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(723, 'Bộ Sách Thú Vị Dành Cho Bé Nhập Môn Tập Tô - Bé Tập Tô Màu - Màu Xanh Lá Cây', '8935210285997', '2021', 47, 279, 20, 23, 32, 'trong_nuoc', 'Bìa Mềm', 'Bộ Sách Thú Vị Dành Cho Bé Nhập Môn Tập Tô - Bé Tập Tô Màu - Màu Xanh Lá Cây\nBộ sách thú vị dành cho bé nhập môn tập tô: Bé Tập Tô Màu - Màu Hồng (2-6 tuổi)\nCác bé ở lứa tuổi mầm non và mẫu giáo luôn muốn khám phá và tìm hiểu thế giới xung quanh. Tập tô là cách hữu ích giúp bé hoàn thiện được sự phát triển về thẩm mĩ. Với các bức hình sinh động, màu sắc tươi tắn, cuốn sách sẽ giúp bé có những giờ phút vui vẻ khi tô màu, phát triển thị giác, tư duy và rèn luyện sự khéo léo của đôi bàn tay.\nTrong cuốn sách, người biên soạn đã nhìn từ góc độ của trẻ em ở lứa tuổi này để chọn ra những bức tranh có màu sắc tươi sáng, hình ảnh sinh động có chủ đề là cuộc sống hàng ngày để cho bé tập tô. Mỗi một bức tranh đều có các bước tô màu để hướng dẫn cho bé từng bước tiến hành luyện tập, đồng thời có lời hướng dẫn cách phối hợp màu sắc, bồi dưỡng những kỹ năng tô màu và khả năng tư duy lôgic của bé. Dần dần các bé sẽ nắm bắt được những quy tắc cơ bản về hội họa và màu sắc.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935210285997.jpg', 28000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(724, 'Từ Điển Bằng Tranh - Thế Giới Động Vật (Tái Bản)', '8935236428392', '2022', 28, 293, 2, 45, 31, 'trong_nuoc', 'Bìa Cứng', 'Cuốn sách với nhiều hình ảnh sinh động về các loài động vật gần gũi và quen thuộc mà bé bắt gặp hằng ngày hay những loài vật mà bé ít được biết đến như: cá mao tiên, rắn san hô, chim hồng tước, cá nhím… giúp bé phát triển khả năng nhận biết.\nCuốn sách còn là bộ sưu tập thu nhỏ với nhiều hình ảnh gần gũi quen thuộc và mới lạ giúp bé trở nên thích thú.\nBên cạnh đó hình thức song ngữ giúp bé gia tăng vốn từ vựng cả về Tiếng Việt lẫn Tiếng Anh. Cuốn sách cũng là tài liệu học từ vựng cho bất cứ bạn nhỏ nào yêu thích môn Tiếng Anh. Các bạn nhỏ có thể vừa học được từ vựng vừa học được cách phát âm.\nBộ sách có thiết kế hợp lý, hình ảnh đẹp, màu sắc bắt mắt giúp bé hào hứng tiếp cận các kiến thức dễ dàng và hiệu quả và đây không còn là những trang sách đầy chữ dày cộm, khô cứng. Cuốn Từ điển bằng tranh theo phương pháp giáo dục sớm GLENN DOMAN cho học sinh là một sự thay đổi bước ngoặt để đưa từ điển đến gần với học sinh, tạo cảm hứng học tập, hứng khởi tìm hiểu, thông qua hình ảnh minh họa để học từ vựng. Sách được in đẹp theo tiêu chuẩn của Anh quốc, giá bìa thấp để có thể đến tay nhiều đối tượng người đọc hơn.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935236428392.jpg', 96000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(725, 'Từ Điển Bằng Tranh - Cờ Các Quốc Gia Trên Thế Giới (Tái Bản 2023)', '8935236429337', '2023', 28, 293, 2, 45, 31, 'trong_nuoc', 'Bìa Mềm', 'Chúng ta cùng mở cuốn sách ra và khám phá xem có những quốc gia nào nhé !', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935236429337.jpg', 92000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(726, 'Kéo Đẩy Tìm Kiếm - 100 Từ Vựng Song Ngữ Việt-Anh Cho Bé', '8935212367684', '2024', 10, 294, 13, 1, 31, 'trong_nuoc', 'Bìa Cứng', 'Kéo Đẩy Tìm Kiếm - 100 Từ Vựng Song Ngữ Việt-Anh Cho Bé\nĐẶC ĐIỂM ƯU VIỆT CỦA CUỐN SÁCH\n- Hình ảnh siêu đẹp, mô phỏng cho các từ vựng về nhiều chủ đề như: động vật, xe cộ, đồ dùng học tập, vật dụng gia đình…\n- Dưới mỗi hình ảnh là từ vựng Tiếng Việt. Và chỉ cần trẻ kéo những thanh bìa cứng là những từ vựng tiếng Anh tương ứng hiện ra, thú vị như một trò chơi lại giúp trẻ ghi nhớ tốt hơn.\n- Mỗi trang sẽ đan cài những câu hỏi đơn giản, khuyến khích trẻ quan sát. tìm kiếm và tìm hiểu về thật nhiều sự vật xung quanh mình.\n- Cách KÉO - ĐẨY độc đáo giúp ba mẹ dễ dàng tương tác và cùng trẻ học từ vựng song ngữ Việt - Anh hiệu quả, vui vẻ.\nTrang sách bìa cứng giúp sản phẩm bền hơn, nhất là với cách thức sử dụng sản phẩm của trẻ nhỏ.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212367684.jpg', 144000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(727, 'Từ Điển Bằng Tranh - Rau Củ Quả (Tái Bản 2023)', '8935236429320', '2023', 28, 293, 2, 45, 31, 'trong_nuoc', 'Bìa Mềm', 'Cuốn sách với nhiều hình ảnh sinh động về các loại rau củ quả khác nhau giúp bé phát triển khả năng nhận biết. Cuốn sách còn là bộ sưu tập với nhiều hình ảnh gần gũi quen thuộc giúp bé trở nên thích thú.\nBên cạnh đó hình thức song ngữ giúp bé gia tăng vốn từ vựng cả về Tiếng Việt lẫn Tiếng Anh. Cuốn sách cũng là tài liệu học từ vựng cho bất cứ bạn nhỏ nào yêu thích môn Tiếng Anh. Các bạn nhỏ có thể vừa học được từ vựng vừa học được cách phát âm.\nBộ sách có thiết kế hợp lý, hình ảnh đẹp, màu sắc bắt mắt giúp bé hào hứng tiếp cận các kiến thức dễ dàng và hiệu quả và đây không còn là những trang sách đầy chữ dày cộm, khô cứng. Cuốn Từ điển bằng tranh theo phương pháp giáo dục sớm GLENN DOMAN cho học sinh là một sự thay đổi bước ngoặt để đưa từ điển đến gần với học sinh, tạo cảm hứng học tập, hứng khởi tìm hiểu, thông qua hình ảnh minh họa để học từ vựng. Sách được in đẹp theo tiêu chuẩn của Anh quốc, giá bìa thấp để có thể đến tay nhiều đối tượng người đọc hơn.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935236429320.jpg', 92000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(728, 'Từ Điển Tiếng Việt Dành Cho Học Sinh - Khổ Nhỏ', '8935236436182', '2024', 1120, 295, 2, 45, 31, 'trong_nuoc', 'Bìa Mềm', 'Từ Điển Tiếng Việt Dành Cho Học Sinh - Khổ Nhỏ\nTừ điển tiếng Việt (Dành cho học sinh) được PGS.TS Phạm Văn Tình nguyên Tổng thư ký Hội Ngôn ngữ học Việt Nam hướng dẫn biên soạn có nội dung đầy đủ, lượng từ vựng phong phú, mang tính chính xác cao. Cách trình bày từ điển khoa học, giải thích rõ ràng. Đặc biệt, tác giả đã đưa ra nhiều ví dụ trích dẫn từ ca dao, tục ngữ và những tác phẩm trong chương trình học phổ thông, nhằm giúp các em học sinh có thêm kiến thức về kho tàng văn học Việt Nam.\nĐặc biệt , tác giả đã đưa ra nhiều ví dụ trích dẫn từ ca dao , tục ngữ và những tác phẩm trong chương trình học phổ thông , nhằm giúp các em học sinh có thêm nhiều kiến thức về kho tàng văn học Việt Nam .\nTừ điển tiếng việt dành cho học sinh là một cuốn từ điển tiếng Việt thông dụng, cung cấp cho học sinh từ lớp 1 đến lớp 12 tra cứu nghĩa của các từ, ngữ, thành ngữ, điển tích, tên riêng... Sách được biên soạn theo chương trình sách giáo khoa, giúp học sinh ôn tập và củng cố kiến thức tiếng Việt.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/z/6/z6158516368028_63f5bd82ebd4d5652322065bbdf24fb3.jpg', 52000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(729, 'Từ Điển Hình Ảnh Cho Bé - Động Vật (Tái Bản 2019)', '8935244828498', '2019', 12, 296, 17, 6, 31, 'trong_nuoc', 'Bìa Mềm', 'Bộ sách gồm 10 cuốn, với các chủ đề: Chữ cái, Số đếm, Màu sắc và hình dạng, Động vật; Hoa, Trái cây, Rau củ, Phương tiện, Đồ dùng, Đồ chơi. Mỗi chủ đề gồm 14 hình ảnh quen thuộc gần gũi với bé và các từ tương ứng với nó (bằng cả tiếng Việt và tiếng Anh) nhằm giúp các bé từ 0-3 tuổi có được vốn từ cần thiết, để bé có những hình dung bước đầu về thế giới xung quanh; đồng thời với vốn từ nho nhỏ này bé sẽ biểu đạt ý nghĩ của mình tốt hơn. Bộ sách có thể coi là những cuốn sách giáo khoa đầu đời dạy bé những bài học đầu tiên đơn giản mà vô cùng ý nghĩa; từ đó bé có thể tự tin trong  giao tiếp.\nSách in trên giấy Ivory, hình ảnh tươi sáng, vui mắt, phần từ ngữ in to dễ đọc, khổ 12,5 x 12,5 cm thích hợp vừa làm sách vừa làm đồ chơi bền bỉ cho các bé 0-3 tuổi.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_188750.jpg', 27000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(730, 'Children\'S Illustrated Thesaurus - Từ Điển Đồng Nghĩa Dành Cho Trẻ Em', '8935212352932', '2021', 256, 168, 21, 1, 31, 'trong_nuoc', 'Bìa Mềm', 'Children\'s Illustrated Thesaurus - Từ điển đồng nghĩa dành cho trẻ em\nChứa hơn 4,000 mục từ Anh-Việt. Mỗi mục từ bao gồm định nghĩa và ví dụ, cùng những bức tranh sinh động để làm rõ ngữ nghĩa của từ.\nĐặc biệt mỗi mục từ được đi kèm nhiều từ đồng nghĩa tiếng Anh, sẽ giúp cho trẻ có được một nguồn kiến thức về từ vựng tuyệt vời để thực hiện những bài viết, bài thuyết trình hấp dẫn, chuyên nghiệp, hay đơn giản là giúp trẻ có kỹ năng nói tốt hơn với cách sử dụng từ ngữ phong phú và đa dạng hơn\nDễ theo dõi, dễ sử dụng, và có rất nhiều thông tin. Cuốn từ điển cung cấp cho trẻ một nguồn đáng tin cậy và tiện lợi để xây dựng vốn từ chất lượng đồng thời tăng khả năng tiếp thu của trẻ về thế giới xung quanh.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_223379.jpg', 228500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(731, 'Từ Điển Bằng Tranh - Nghề Nghiệp - Bìa Cứng', '8935236438063', '2025', 30, 297, 2, 45, 31, 'trong_nuoc', 'Bìa Cứng', 'Từ Điển Bằng Tranh - Nghề Nghiệp\nCuốn sách siêu dễ thương dành cho bé yêu!\nGiúp bé khám phá hơn 30 nghề nghiệp quen thuộc qua hình ảnh sinh động.\nTăng vốn từ vựng – kích thích sự tò mò – phát triển tư duy nghề nghiệp sớm.\nTranh minh họa rõ ràng, màu sắc tươi sáng, phù hợp cho bé từ 2–7 tuổi.\nHọc bằng mắt – nhớ bằng hình – bé mê tít luôn!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935236438063.jpg', 102000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
