(734, 'Từ Điển Bằng Hình Đầu Tiên Của Bé - Opposite - Đối Lập', '9786045693650', '2021', 16, 299, 53, 50, 31, 'trong_nuoc', 'Bìa Cứng', 'Bộ sách có thể coi là những cuốn sách giáo khoa đầu đời dạy bé những bài học đầu tiên đơn giản mà vô cùng ý nghĩa; từ đó bé có thể tự tin trong giao tiếp.\nSách in bìa cứng, hình ảnh tươi sáng, vui mắt, phần từ ngữ in to dễ đọc, khổ 12 x 12 cm thích hợp vừa làm sách vừa làm đồ chơi bền bỉ cho các bé 0-6 tuổi.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_240047.jpg', 23500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(735, 'Từ Điển Bằng Tranh Dành Cho Trẻ Em - Màu Sắc Và Hình Dạng', '8935212363471', '2023', 16, 300, 12, 1, 31, 'trong_nuoc', 'Bìa Mềm', 'Từ Điển Bằng Tranh Dành Cho Trẻ Em - Màu Sắc Và Hình Dạng\nBộ sách bao gồm:\nTừ điển bằng tranh dành cho trẻ em - Rau củ\nTừ điển bằng tranh dành cho trẻ em - Động vật\nTừ điển bằng tranh dành cho trẻ em - Phương tiện giao thông\nTừ điển bằng tranh dành cho trẻ em - Nghề nghiệp\nTừ điển bằng tranh dành cho trẻ em - Thức ăn\nTừ điển bằng tranh dành cho trẻ em - Các loài hoa\nTừ điển bằng tranh dành cho trẻ em - Vật dụng gia đình\nTừ điển bằng tranh dành cho trẻ em - Đồ dùng của bé\nTừ điển bằng tranh dành cho trẻ em - Thế giới quanh em\nTừ điển bằng tranh dành cho trẻ em - Màu sắc và Hình dạng\nTừ điển bằng tranh dành cho trẻ em - Quốc kỳ', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212363471.jpg', 20000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
