(738, 'Từ Điển Bằng Tranh Dành Cho Trẻ Em - Quốc Kỳ', '8935212363488', '2023', 16, 300, 12, 1, 31, 'trong_nuoc', 'Bìa Mềm', 'Từ Điển Bằng Tranh Dành Cho Trẻ Em - Quốc Kỳ\nBộ sách bao gồm:\nTừ điển bằng tranh dành cho trẻ em - Rau củ\nTừ điển bằng tranh dành cho trẻ em - Động vật\nTừ điển bằng tranh dành cho trẻ em - Phương tiện giao thông\nTừ điển bằng tranh dành cho trẻ em - Nghề nghiệp\nTừ điển bằng tranh dành cho trẻ em - Thức ăn\nTừ điển bằng tranh dành cho trẻ em - Các loài hoa\nTừ điển bằng tranh dành cho trẻ em - Vật dụng gia đình\nTừ điển bằng tranh dành cho trẻ em - Đồ dùng của bé\nTừ điển bằng tranh dành cho trẻ em - Thế giới quanh em\nTừ điển bằng tranh dành cho trẻ em - Màu sắc và Hình dạng\nTừ điển bằng tranh dành cho trẻ em - Quốc kỳ', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212363488.jpg', 20000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(739, 'Tớ Chọn Người Mẹ Này (2+)', '8935280904859', '2019', 37, 302, 18, 9, 31, 'trong_nuoc', 'Bìa Mềm', 'Cuốn truyện tranh này được ra đời sau khi tôi gặp gỡ những trẻ có được ký ức về khoảng thời gian còn ở trong bụng mẹ mình. Tôi vô cùng ngạc nhiên lúc hỏi các cháu: “Tại sao các cháu ra đời?” thì tất cả đều trả lời: “Tất nhiên là để làm cho mẹ vui rồi ạ!” Hóa ra, trẻ luôn tự tin mình sẽ đem lại niềm vui cho mẹ rồi cho cả những người xung quanh. Trẻ luôn mong muốn mẹ sẽ vui với những việc mình làm, nhưng mẹ lại luôn la mắng trẻ. Nếu có thể làm mẹ vui, trẻ cũng sẽ làm cho những người xung quanh vui.\nNếu ai cũng vui thì xã hội này sẽ tốt đẹp biết bao. Việc đó hoàn toàn phụ thuộc vào việc mẹ có vui hay không đấy!', NULL, 'https://cdn1.fahasa.com/media/catalog/product/t/o/to_chon_nguoi_me_nay_2_1_2020_05_09_12_15_47.JPG', 46500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(740, 'Từ Điển Bằng Hình Cho Trẻ Mầm Non - Động Vật (Tái Bản 2020)', '8936071676672', '2019', 48, 22, 14, 8, 31, 'trong_nuoc', 'Bìa Cứng', 'Từ Điển Bằng Hình Cho Trẻ Mầm Non - Động Vật (Tái Bản 2020)\nLà cuốn sách tranh màu tuyệt vời dành cho các bậc phụ huynh muốn cùng chia sẻ với con cái. Với những hình ảnh dễ thương về đồ vật giúp bé khám phá và học hỏi, cuốn sách này sẽ giúp bé xây dựng vốn từ vựng, học phân biệt màu sắc, luyện đếm số và phát triển kỹ năng quan sát.\nCuốn sách gồm có các chủ đề đa dạng, phong phú gắn liền với cuộc sống hàng ngày, sách có tác dụng làm cho bé dễ hiểu và hăng hái hơn trong việc học ngoại ngữ như Kệ đồ chơi, Động vật, Trong vườn, Màu sắc, Ở trường. Chấm và sọc, Trên bãi biển, Trong bếp, Phương tiện giao thông, Chơi nấu ăn, Xây dựng, Đen trắng, v…v… Các bậc phụ huynh nên tập cho bé phát âm những từ tiếng Anh đơn giản để làm quen và cùng chơi với bé. Bé sẽ hào hứng kết thân với thế giới xung quanh qua việc tìm các đồ vật đã trốn kĩ trong tranh, từ đó dần nhận biết các đồ vật quen thuộc trong cuộc sống hàng ngày. Phương pháp giáo dục trực quan mới mẻ sẽ giúp con bạn ngày càng hào hứng, say mê tìm hiểu và khám phá thế giới.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_244718_1_5020.jpg', 127500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(741, 'Bộ Từ Điển Bằng Tranh Dành Cho Trẻ Em 1 (Bộ 6 Cuốn)', '8935212363877', '2023', NULL, 300, 12, 1, 31, 'trong_nuoc', 'Bìa Mềm', 'Bộ Từ Điển Bằng Tranh Dành Cho Trẻ Em 1 (Bộ 6 Cuốn)\nBộ sách bao gồm:\nTừ điển bằng tranh dành cho trẻ em - Thức ăn\nTừ điển bằng tranh dành cho trẻ em - Thế giới quanh em\nTừ điển bằng tranh dành cho trẻ em - Rau củ\nTừ điển bằng tranh dành cho trẻ em - Động vật\nTừ điển bằng tranh dành cho trẻ em - Các loài hoa\nTừ điển bằng tranh dành cho trẻ em - Trái Cây', NULL, 'https://cdn1.fahasa.com/media/catalog/product/z/4/z4178446243587_3dcd7394e7d27d85613618f57cb3ea7a.jpg', 120000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(742, 'Từ Điển Bằng Hình Cho Trẻ Mầm Non - Những Từ Đầu Tiên (Tái Bản 2019)', '8936071676689', '2019', 48, 22, 14, 8, 31, 'trong_nuoc', 'Bìa Mềm', 'Trốn tìm – Những chữ cái đầu tiên là cuốn sách tranh màu tuyệt vời dành cho các bậc phụ huynh cùng chia sẻ với con. Với những hình ảnh dễ thương về đồ vật giúp bé khám phá và học hỏi, cuốn sách này sẽ giúp bé xây dựng vốn từ vựng, học phân biệt màu sắc, luyện đếm số và phát triển kỹ năng quan sát. Các bé sẽ hào hứng làm quen với thế giới xung quanh qua việc tìm các đồ vật đã trốn kĩ trong tranh, từ đó dần nhận biết các đồ vật quen thuộc trong cuộc sống hàng ngày. Phương pháp giáo dục trực quan mới mẻ sẽ giúp trẻ ngày càng hào hứng, say mê tìm hiểu thế giới.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_31103.jpg', 127500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(743, 'Bộ Từ Điển Bằng Hình Cho Bé (Bộ 6 Cuốn)', '8935212359696', '2022', 144, 22, 13, 1, 31, 'trong_nuoc', 'Bìa Mềm', 'Bộ Từ Điển Bằng Hình Cho Bé (Bộ 6 Cuốn)\nTừ điển bằng hình cho bé là bộ sách tuyệt vời để các bậc phụ huynh chia sẻ những khoảng thời gian vừa học vừa chơi thú vị bên bé yêu. Với những ưu điểm như:\nCác chủ đề gần gũi, thân thiện với cuộc sống thường nhật.\nNội dung song ngữ Việt – Anh kèm theo phiên âm, giúp bé bước đầu làm quen với ngôn ngữ thứ hai ngoài tiếng mẹ đẻ\nHình ảnh thật trong sách giúp bé có thể nhận biết sự vật một cách trực quan nhất\nMàu sắc tươi sáng, sống động, bắt mắt giúp bé hứng thú tìm hiểu về thế giới xung quanh\nChúng tôi tin bộ sách sẽ là món quà bổ ích để giúp các bậc phụ huynh dành tặng con em mình\nBộ sách gồm các chủ đề', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212359696.jpg', 134000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(744, 'Bộ Từ Điển Bằng Tranh Dành Cho Trẻ Em 2 (Bộ 6 Cuốn)', '8935212363884', '2023', NULL, 300, 12, 1, 31, 'trong_nuoc', 'Bìa Mềm', 'Bộ Từ Điển Bằng Tranh Dành Cho Trẻ Em 2 (Bộ 6 Cuốn)\nBộ sách bao gồm:\nTừ điển bằng tranh dành cho trẻ em - Nghề nghiệp\nTừ điển bằng tranh dành cho trẻ em - Màu sắc và hình dạng\nTừ điển bằng tranh dành cho trẻ em - Vật dụng gia đình\nTừ điển bằng tranh dành cho trẻ em - Đồ dùng của bé\nTừ điển bằng tranh dành cho trẻ em - Phương tiện giao thông\nTừ điển bằng tranh dành cho trẻ em - Quốc kỳ', NULL, 'https://cdn1.fahasa.com/media/catalog/product/z/4/z4178446235171_a85a2d3595a1d395f995ae8a0e2531c6.jpg', 120000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(745, 'Từ Điển Hình Ảnh Cho Bé - Chữ Cái Tiếng Anh', '8931805678045', '2020', 16, 282, 54, 36, 31, 'trong_nuoc', 'Bìa Cứng', 'Cuốn sách giúp bé dễ dàng nhận biết và ghi nhớ bảng chữ cái tiếng Anh. Hình ảnh minh họa sắc nét và chân thật, màu sắc sinh động của cuốn sách sẽ thu hút sự chú ý của các bé. Chữ Cái Tiếng Anh  - Từ Điển Hình Ảnh Cho Bé sẽ giúp cha mẹ xây dựng thói quen đọc sách, niềm say mê đối với sách cho các con ngay từ bé.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_43904.jpg', 25500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(746, 'Từ Điển Hình Ảnh Cho Bé - Trái Cây', '8931805678052', '2020', 16, 282, 55, 36, 31, 'trong_nuoc', 'Bìa Cứng', 'Cuốn sách giúp bé dễ dàng nhận biết và làm quen với các loại trái cây quen thuộc. Hình ảnh minh họa sắc nét và chân thật, màu sắc sinh động của cuốn sách sẽ thu hút sự chú ý của các bé. Trái Cây - Từ Điển Hình Ảnh Cho Bé sẽ giúp cha mẹ xây dựng thói quen đọc sách, niềm say mê đối với sách cho các con ngay từ bé.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_43905.jpg', 25500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(747, 'Từ Điển Bằng Hình Cho Bé - Các Loài Động Vật - Animals', '8935212358378', '2022', 24, 22, 13, 1, 31, 'trong_nuoc', 'Bìa Mềm', 'Từ Điển Bằng Hình Cho Bé - Các Loài Động Vật - Animals\nTừ điển bằng hình cho bé là bộ sách tuyệt vời để các bậc phụ huynh chia sẻ những khoảng thời gian vừa học vừa chơi thú vị bên bé yêu. Với những ưu điểm như :\n- Các chủ đề gần gũi, thân thiện với cuộc sống thường nhật.\n- Nội dung song ngữ Việt – Anh kèm theo phiên âm, giúp bé bước đầu làm quen với ngôn ngữ thứ hai ngoài tiếng mẹ đẻ\n- Hình ảnh thật trong sách giúp bé có thể nhận biết sự vật một cách trực quan nhất\n- Màu sắc tươi sáng, sống động, bắt mắt giúp bé hứng thú tìm hiểu về thế giới xung quanh\n- Chúng tôi tin bộ sách sẽ là món quà bổ ích để giúp các bậc phụ huynh dành tặng con em mình\nBộ sách gồm các chủ đề', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935212358378.jpg', 22000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(748, 'Siêu Cao Thủ Đầu Tư: Bài Học Từ 20 Nhà Đầu Tư Vĩ Đại Nhất Thế Giới', '8934974185062', '2023', 332, 303, 22, 24, 31, 'trong_nuoc', NULL, 'Dựa trên chuyên mục \'Những nhà đầu tư vĩ đại trong lịch sử\' nổi tiếng của MoneyWeek, sách sẽ đưa ra một cái nhìn sâu sắc về 20 nhà đầu tư giỏi nhất trong 200 năm qua và chỉ cho độc giả cách học hỏi họ.\nNhững nhà đầu tư này đã được chọn theo nhiều tiêu chí, bao gồm khả năng đầu tư xuất sắc của họ, cách kiếm tiền, và trên hết là những gì họ có thể dạy cho các nhà đầu tư cá nhân. Các nhà đầu tư siêu hạng thuộc nhiều phong cách đầu tư khác nhau, từ David Ricardo, người kiếm được nhiều tiền nhờ dự đoán chính xác kết quả của trận Waterloo, đến cách tiếp cận theo định hướng giá trị đầy kiên nhẫn của Warren Buffett. Cuốn sách cũng xem xét một số nhà đổi mới, bao gồm việc John Bogle phát triển quỹ chỉ số như một cách tiếp cận thị trường với chi phí thấp và cách tiếp cận theo hướng dữ liệu của David Harding nhằm mục đích tránh cảm xúc của con người.\nSách thể hiện các hành động, tương tác của các nhà đầu tư với thị trường chứng khoán, trình bày phương pháp đầu tư của từng người, bao gồm những thương vụ đầu tư nổi bật, có điểm nhấn, những phi vụ nổi tiếng, từng gây chấn động thế giới. Ở cuối mỗi phần có phần tóm tắt các chiến lược súc tích, thuận lợi cho người đọc; có xếp hạng, chấm điểm nhà đầu tư ở cuối mỗi chương. \n ', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8934974185062.jpg', 119000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(749, 'Làm Mẹ Với Tâm Phật - Cùng Con Chào Đời', '8935280908727', '2021', 260, 304, 12, 9, 31, 'trong_nuoc', 'Bìa Mềm', 'Khi những người phụ nữ bước vào giai đoạn làm mẹ, họ có thể bị xáo trộn tâm lý. Trước mắt họ có thể đầy những thử thách, những đêm mất ngủ, thời gian ở nhà nhiều và còn hiếm khi tìm thấy thời gian cho bản thân. Một số người có thể cảm thấy tức giận, mệt mỏi, thất vọng, thậm chí gây ra những hành động bạo lực không đáng có. Sự tức giận đó thật ra là vô ích và có hại.\nĐã có nhiều cuốn sách chỉ dẫn việc nuôi dạy con cái, nhưng hiếm khi đề cập tới những bà mẹ vất vả đang chăm bẵm những đứa con của mình. Những tài liệu Phật giáo thì cũng ít chú ý đến hoàn cảnh của những bà mẹ.\nNhận thức được nỗi khổ, thậm chí là tuyệt vọng của nhiều bà mẹ, Sarah Napthali đã viết nên một cuốn sách có thể làm thay đổi cuộc sống của những người mẹ. Làm mẹ với tâm Phật: Cùng con chào đời của bà sẽ đưa đến những thực hành Phật giáo để giúp các bà mẹ bình tĩnh hơn, hạnh phúc hơn. Tác giả có cách tiếp cận không cứng nhắc, chọn lọc từ những trường phái Phật giáo nhằm giúp các bà mẹ tránh được những đau khổ và sự bất mãn. Napthali đã chỉ ra rằng: Để hạnh phúc, chúng ta cần thay đổi tâm trí mình.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_237740_1.jpg', 101000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(750, 'Bút Sáp Màu Chicko Regular Crayons - 18 Màu - DK3303-18', '8936178580438', '2020', NULL, NULL, NULL, 18, 31, 'trong_nuoc', NULL, 'Bút Sáp Màu Chicko Regular Crayons - 18 Màu - DK3303-18\nBút sáp màu được làm từ những thành phần không độc hại, giúp bé an toàn khi sử dụng, trơn mịn, không dây bẩn, tiết kiệm khi sử dụng.\nVới 18 màu sắc, trẻ có thể thỏa sức tô vẽ và tạo ra những bức tranh nhiều màu sắc.\nBộ bút sáp không chỉ giúp bé nhận biết về nhiều màu sắc khác nhau mà còn để trẻ tự do phát triển khả năng sáng tạo, pha trộn màu khi tô vẽ nâng cao năng khiếu mỹ thuật của mình.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/i/m/image_195509_1_38186.jpg', 9440.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(751, 'Một Lược Sử Về Vạn Vật', '8936144201862', '2023', 503, 305, 3, 26, 31, 'trong_nuoc', 'Bìa Mềm', 'Một Lược Sử Về Vạn Vật\nMột lược sử về vạn vật là một tác phẩm vận hành trên nhiều cấp độ.\nBao phủ một phạm vi lịch sử rất rộng, từ Tiếng Nổ Lớn đến tận xã hội hậu hiện đại cằn cỗi ngày nay. Dọc theo tiến trình này, nó cố gắng tìm ra ý nghĩa trong những cách thức có tính mâu thuẫn mà theo đó con người đã tiến hóa - cơ thể, cảm xúc, trí tuệ, đạo đức, và tinh thần.\nTrong cuốn Một lược sử về vạn vật này, Wilber còn đóng vai trò là người vạch trần và làm sáng tỏ - một nhà phê bình rất sáng suốt của những bậc thầy, những kỹ thuật, những ý tưởng cũng như những hệ thống, vốn hứa hẹn sẽ đưa bạn đến với chân lý toàn diện, nhưng thường lại không được đầy đủ, lầm lạc, bị bóp méo, và sẽ khiến bạn lạc lối.\n“Với sự tổng hợp đầy ấn tượng từ nhiều lĩnh vực nghiên cứu khác nhau, Wilber đưa người đọc bước vào hành trình khởi đầu từ Tiếng Nổ Lớn và đi đến tương lai. Ông đã tổ chức và sắp xếp nguồn tư liệu dồi dào của mình sao cho tương hợp với bản chất của quá trình tiến hóa, sử dụng lại chủ đề của những nhà tư tưởng trước đó để xây dựng một “lý thuyết hợp nhất” có tính bước ngoặt trong lịch sử. Thông qua đó, độc giả sẽ có được một cái nhìn mới mẻ hơn về những gì mình đã biết, hay nghĩ rằng mình đã biết, dù là ở bất kỳ lĩnh vực nào đi nữa.”', NULL, 'https://cdn1.fahasa.com/media/catalog/product/z/4/z4332383625683_07d61f11173bac811.jpg', 335500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(752, 'Những Người Quanh Rhett Butler', '8935095623242', '2017', 580, 306, 1, 4, 31, 'trong_nuoc', 'Bìa Mềm', 'Những Người Quanh Rhett Butler\nNhững Người Quanh Rhett Butler là phần tiếp theo của cuốn tiểu thuyết kinh điển Cuốn theo chiều gió do Donald McCaig sáng tác theo ủy quyền của Tổ chức quản lý di sản Margaret Mitchell. Đây là một tác phẩm sinh động, chân thực, đau đớn, mạnh mẽ, làm thỏa mãn trí tò mò và sức tưởng tượng của những độc giả hâm mộ kiệt tác Cuốn theo chiều gió.\nTrong Những Người Quanh Rhett Butler Donald McCaig đã hé mở về thời niên thiếu và thời thanh niên của chàng trai Rhett cho đến khi anh trở thành một doanh nhân thành đạt. Câu chuyện ấy được kể lại qua con mắt của chính Rhett Butler về quãng thời gian trước và sau khi cuộc nội chiến kết thúc. Trong tiểu thuyết gốc, thời gian trước khi anh xuất hiện ở trại Mười hai cây sồi hoàn toàn bí ẩn. Bằng tài năng và sự am hiểu, Donald McCaig đã kể một câu chuyện thực sự hấp dẫn về cuộc sống của Rhett và những người xung quanh anh, những người có ảnh hưởng đến sự hình thành người đàn ông trong anh. Lấy bối cảnh chính là cuộc chiến tranh Nam - Bắc, ngòi bút của Donald McCaig còn khắc họa cuộc sống của những lớp người tiêu biểu trong xã hội đầy biến động.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935095623242.jpg', 142000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(753, 'Rèn Luyện IQ-EQ-CQ Cho Bé - Mẹ Hỏi Bé Trả Lời - Bé Thông Minh Học Cùng Mẹ - Dành Cho Bé 2-3 Tuổi - Bìa Cứng', '9786326062151', '2025', 80, 307, 1, 27, 30, 'trong_nuoc', 'Bìa Cứng', 'Rèn Luyện IQ-EQ-CQ Cho Bé - Mẹ Hỏi Bé Trả Lời - Bé Thông Minh Học Cùng Mẹ - Dành Cho Bé 2-3 Tuổi\nBộ sách nhỏ xinh “Mẹ hỏi bé trả lời” là tập hợp những trò chơi phong phú, câu đố thông minh giúp bé và cha mẹ có thể “học mà chơi, chơi mà học” qua các chủ đề: cách ứng xử, câu hỏi về tự nhiên, không gian, phân biệt hình khối, ngôn ngữ, toán học...\nSách phân chia theo từng lứa tuổi với nội dung phong phú, những câu hỏi đáp hàm súc trí tuệ, hình ảnh dễ thương cùng nhiều phương pháp rèn luyện có thể khơi dậy trí thông minh và khả năng tiềm ẩn của bé.\nBộ sách “Mẹ Hỏi Bé Trả Lời” gồm:\n- Mẹ Hỏi Bé Trả Lời 1-2 Tuổi\n- Mẹ Hỏi Bé Trả Lời 2-3 Tuổi', NULL, 'https://cdn1.fahasa.com/media/catalog/product/9/7/9786326062151.jpg', 27000.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
(754, 'Rèn Luyện IQ-EQ-CQ Cho Bé - Mẹ Hỏi Bé Trả Lời - Bé Thông Minh Học Cùng Mẹ - 2-3 Tuổi - Bìa Cứng', '8935230010654', '2026', 80, 307, 1, 27, 30, 'trong_nuoc', 'Bìa Cứng', 'Rèn Luyện IQ-EQ-CQ Cho Bé - Mẹ Hỏi Bé Trả Lời - Bé Thông Minh Học Cùng Mẹ - 2-3 Tuổi\nBộ sách “Mẹ hỏi bé trả lời” gồm 5 cuốn, được thiết kế dành cho trẻ nhỏ trong những năm đầu đời. Mỗi cuốn là tập hợp các câu hỏi gần gũi xoay quanh thế giới xung quanh bé, giúp bé học cách quan sát, suy nghĩ và diễn đạt bằng ngôn ngữ của mình. Thông qua hình ảnh sinh động và nội dung đơn giản, bộ sách không chỉ hỗ trợ phát triển tư duy ngôn ngữ mà còn tạo cơ hội để mẹ và bé cùng trò chuyện, gắn kết và học hỏi mỗi ngày.', NULL, 'https://cdn1.fahasa.com/media/catalog/product/8/9/8935230010654.jpg', 28500.00, NULL, 20, '2026-03-10 11:42:54', '2026-03-10 11:42:54'),
